app.get("/sw.js", (req, res) => {
  res.setHeader("Content-Type", "application/javascript; charset=utf-8");
  res.setHeader("Cache-Control", "no-store");

  res.send(`
const CACHE_NAME = "iqg-dashboard-pwa-v1";
const STATIC_ASSETS = [
  "/iqg-icon.svg"
];

self.addEventListener("install", event => {
  self.skipWaiting();

  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => cache.addAll(STATIC_ASSETS))
      .catch(() => null)
  );
});

self.addEventListener("activate", event => {
  event.waitUntil(
    caches.keys()
      .then(keys => Promise.all(
        keys
          .filter(key => key !== CACHE_NAME)
          .map(key => caches.delete(key))
      ))
      .then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", event => {
  const requestUrl = new URL(event.request.url);

  // NĂŁo cachear dashboard, leads, rotas POST, APIs ou dados sensĂ­veis.
  if (
    event.request.method !== "GET" ||
    requestUrl.pathname.startsWith("/dashboard") ||
    requestUrl.pathname.startsWith("/lead/") ||
    requestUrl.pathname.startsWith("/conversation/") ||
    requestUrl.pathname.startsWith("/webhook")
  ) {
    return;
  }

  if (requestUrl.pathname === "/iqg-icon.svg") {
    event.respondWith(
      caches.match(event.request).then(cached => {
        return cached || fetch(event.request);
      })
    );
  }
});
`);
});

const client = new MongoClient(process.env.MONGODB_URI);
let db;

/* =========================
   đ„ MONGODB (CORRIGIDO)
========================= */

async function connectMongo() {
  try {
    if (!db) {
      await client.connect();
      db = client.db("iqg");
      console.log("đ„ Mongo conectado");
      return;
    }

    await db.command({ ping: 1 });
  } catch (error) {
    console.error("â ïž Mongo desconectado. Tentando reconectar...", error.message);

    try {
      await client.close().catch(() => {});
      await client.connect();
      db = client.db("iqg");
      console.log("đ„ Mongo reconectado");
    } catch (reconnectError) {
      console.error("â Falha ao reconectar Mongo:", reconnectError);
      throw reconnectError;
    }
  }
}

async function claimMessage(messageId) {
  if (!messageId) return true;

  await connectMongo();

  try {
    await db.collection("processed_messages").insertOne({
      _id: messageId,
      createdAt: new Date()
    });

    return true;
  } catch (error) {
    if (error.code === 11000) {
      return false;
    }

    throw error;
  }
}

async function ensureIndexes() {
  await connectMongo();

  await db.collection("processed_messages").createIndex(
    { createdAt: 1 },
    { expireAfterSeconds: 86400 }
  );

  await db.collection("leads").createIndex(
    { user: 1 },
    { unique: true }
  );

  await db.collection("conversations").createIndex(
    { user: 1 },
    { unique: true }
  );

  await db.collection("incoming_message_buffers").createIndex(
    { updatedAt: 1 },
    { expireAfterSeconds: 300 }
  );

    await db.collection("internal_alert_locks").createIndex(
    { createdAt: 1 },
    { expireAfterSeconds: 3600 }
  );

   await db.collection("file_send_logs").createIndex(
    { createdAt: 1 },
    { expireAfterSeconds: 7 * 24 * 60 * 60 }
  );

await db.collection("scheduled_callbacks").createIndex(
    { status: 1, scheduledDate: 1 }
  );

  await db.collection("scheduled_callbacks").createIndex(
    { user: 1 }
  );

  await db.collection("scheduled_callbacks").createIndex(
    { createdAt: 1 },
    { expireAfterSeconds: 30 * 24 * 60 * 60 }
  );
   
  await db.collection("crm_send_logs").createIndex(
    { createdAt: 1 },
    { expireAfterSeconds: 30 * 24 * 60 * 60 }
  );
}

async function updateLeadStatus(user, status) {
  await connectMongo();

  const currentLead = await db.collection("leads").findOne({ user });

  /*
    BLOCO 9B:
    O status alterado pelo dashboard passa a ser VISUAL/OPERACIONAL HUMANO.
    Ele NĂO deve comandar a prĂłxima decisĂŁo da IA, exceto quando for
    "em_atendimento", que significa humano assumiu a conversa.
  */

  const dashboardPatch = {
    statusDashboard: status,
    statusVisualDashboard: status,
    ultimoStatusDashboard: status,
    statusDashboardAtualizadoEm: new Date(),
    atualizadoPeloDashboard: true
  };

 if (status === "em_atendimento") {
    // Toggle: se jĂĄ estĂĄ em atendimento humano, reverter
    if (
      currentLead?.humanoAssumiu === true ||
      currentLead?.atendimentoHumanoAtivo === true ||
      currentLead?.status === "em_atendimento"
    ) {
      const statusAnterior = currentLead?.statusAnteriorDashboard || "morno";
      const faseAnterior = currentLead?.faseAnteriorDashboard || "morno";

      await db.collection("leads").updateOne(
        { user },
        {
          $set: {
            ...dashboardPatch,
            status: statusAnterior,
            faseQualificacao: faseAnterior,
            statusOperacional: "ativo",
            humanoAssumiu: false,
            atendimentoHumanoAtivo: false,
            botBloqueadoPorHumano: false,
            liberadoDoAtendimentoHumanoEm: new Date(),
            updatedAt: new Date()
          }
        }
      );

      console.log("â Dashboard reverteu atendimento humano:", {
        user,
        para: statusAnterior
      });

      return;
    }

    // Salvar status anterior para poder reverter
    await db.collection("leads").updateOne(
      { user },
      {
        $set: {
          statusAnteriorDashboard: currentLead?.status || "morno",
          faseAnteriorDashboard: currentLead?.faseQualificacao || "morno",
        }
      }
    );
    const lifecycleData = getLeadLifecycleFields({
      ...(currentLead || {}),
      status: "em_atendimento",
      faseQualificacao: "em_atendimento"
    });

    lifecycleData.statusOperacional = "em_atendimento";
    lifecycleData.faseFunil = "crm";
    lifecycleData.temperaturaComercial =
      currentLead?.temperaturaComercial || "indefinida";
    lifecycleData.rotaComercial =
      currentLead?.rotaComercial ||
      currentLead?.origemConversao ||
      "homologado";

    await db.collection("leads").updateOne(
      { user },
      {
        $set: {
          ...dashboardPatch,

          // ĂNICO status do dashboard que interfere na IA:
          status: "em_atendimento",
          faseQualificacao: "em_atendimento",

          humanoAssumiu: true,
          atendimentoHumanoAtivo: true,
          botBloqueadoPorHumano: true,
          assumidoPorHumanoEm: new Date(),

          ...lifecycleData,
          updatedAt: new Date()
        }
      }
    );

    console.log("đ§âđŒ Dashboard colocou lead em atendimento humano. IA bloqueada:", {
      user,
      statusDashboard: status
    });

    return;
  }

  /*
    Se o lead estava em atendimento humano e o dashboard mudou para outro status,
    liberamos a IA novamente.

    Importante:
    Mesmo liberando a IA, NĂO usamos o novo status visual como fase da IA.
    O fluxo conversacional serĂĄ reavaliado pelo histĂłrico e pelo backend.
  */
  const liberarAtendimentoHumano =
    currentLead?.botBloqueadoPorHumano === true ||
    currentLead?.humanoAssumiu === true ||
    currentLead?.atendimentoHumanoAtivo === true ||
    currentLead?.statusOperacional === "em_atendimento" ||
    currentLead?.status === "em_atendimento" ||
    currentLead?.faseQualificacao === "em_atendimento";

  if (liberarAtendimentoHumano && status !== "fechado" && status !== "perdido") {
    await db.collection("leads").updateOne(
      { user },
      {
        $set: {
          ...dashboardPatch,

          humanoAssumiu: false,
          atendimentoHumanoAtivo: false,
          botBloqueadoPorHumano: false,
          liberadoDoAtendimentoHumanoEm: new Date(),

          statusOperacional: "ativo",

          /*
            Bug C â limpeza forte do estado de cadĂȘncia ao devolver lead pra IA.
            Sem isso, o proximoFollowupEm antigo (de antes do humano assumir)
            fica residual e o cron pode disparar com base ruim assim que
            botBloqueadoPorHumano vira false. Zeramos aqui e chamamos
            scheduleLeadFollowups na sequĂȘncia, que reagenda do zero
            respeitando o horĂĄrio comercial (Bug B fix).
          */
          proximoFollowupEm: null,
          followupStep: 0,
          followupLockEm: null,

          updatedAt: new Date()
        }
      }
    );

    console.log("â Dashboard liberou lead do atendimento humano. IA pode voltar a responder:", {
      user,
      statusDashboard: status
    });

    try {
      await scheduleLeadFollowups(user);
    } catch (rescheduleError) {
      console.error("Erro ao reagendar follow-up apĂłs liberaĂ§ĂŁo humanoâIA (ignorado):", {
        user,
        error: rescheduleError.message
      });
    }

    return;
  }
   
  /*
  Para status "fechado" e "perdido":
  - muda status real para que o dashboard reflita a aĂ§ĂŁo
  - bloqueia o bot para nĂŁo reabrir conversa
  - libera atendimento humano se estava ativo
  */
  if (status === "fechado" || status === "negociado" || status === "perdido") {
    // Toggle: se jĂĄ estĂĄ neste status, reverter para o anterior
    if (currentLead?.status === status) {
      const statusAnterior = currentLead?.statusAnteriorDashboard || "morno";
      const faseAnterior = currentLead?.faseAnteriorDashboard || "morno";

      await db.collection("leads").updateOne(
        { user },
        {
          $set: {
            ...dashboardPatch,
            status: statusAnterior,
            faseQualificacao: faseAnterior,
            statusOperacional: "ativo",
            humanoAssumiu: false,
            atendimentoHumanoAtivo: false,
            botBloqueadoPorHumano: false,
            liberadoDoAtendimentoHumanoEm: new Date(),
            updatedAt: new Date()
          }
        }
      );

      console.log("â Dashboard reverteu status:", {
        user,
        de: status,
        para: statusAnterior
      });

      return;
    }

    await db.collection("leads").updateOne(
      { user },
      {
        $set: {
          ...dashboardPatch,
          statusAnteriorDashboard: currentLead?.status || "morno",
          faseAnteriorDashboard: currentLead?.faseQualificacao || "morno",
          status: status,
          faseQualificacao: status,
          statusOperacional: status,
          faseFunil: "encerrado",
          humanoAssumiu: false,
          atendimentoHumanoAtivo: false,
          botBloqueadoPorHumano: true,
          // Registra que foi o HUMANO que deu este status pelo dashboard
          origemEncerramento: status === "perdido" ? "humano" : "humano",
          encerradoPor: "humano",
          encerradoEm: new Date(),
          updatedAt: new Date()
        }
      }
    );
    console.log("â Dashboard marcou lead como " + status + ":", {
      user,
      statusAnterior: currentLead?.status
    });

    return;
  }

  // Para qualquer outro status visual
  await db.collection("leads").updateOne(
    { user },
    {
      $set: {
        ...dashboardPatch,
        updatedAt: new Date()
      }
    }
  );

  console.log("đ Dashboard atualizou status visual:", {
    user,
    statusDashboard: status
  });
  console.log("đ·ïž Dashboard atualizou status visual sem interferir na IA:", {
    user,
    statusDashboard: status,
    statusIaAtual: currentLead?.status || "",
    faseIaAtual: currentLead?.faseQualificacao || "",
    statusOperacionalAtual: currentLead?.statusOperacional || ""
  });
}
