function parseSupervisorJson(rawText = "") {
  const fallback = buildDefaultSupervisorAnalysis();

  try {
    const parsed = JSON.parse(rawText);

    return {
      ...fallback,
      ...parsed,
      analisadoEm: new Date()
    };
  } catch (error) {
    try {
      const start = rawText.indexOf("{");
      const end = rawText.lastIndexOf("}");

      if (start === -1 || end === -1 || end <= start) {
        return {
          ...fallback,
          houveErroSdr: true,
          errosDetectados: ["erro_json_supervisor"],
          descricaoErroPrincipal: "Supervisor retornou resposta sem JSON vĂĄlido.",
          riscoPerda: "nao_analisado",
          qualidadeConducaoSdr: "nao_analisado",
          observacoesTecnicas: ["Falha ao localizar objeto JSON na resposta do Supervisor."],
          analisadoEm: new Date()
        };
      }

      const jsonText = rawText.slice(start, end + 1);
      const parsed = JSON.parse(jsonText);

      return {
        ...fallback,
        ...parsed,
        analisadoEm: new Date()
      };
    } catch (secondError) {
      return {
        ...fallback,
        houveErroSdr: true,
        errosDetectados: ["erro_json_supervisor"],
        descricaoErroPrincipal: "Supervisor retornou JSON invĂĄlido.",
        riscoPerda: "nao_analisado",
        qualidadeConducaoSdr: "nao_analisado",
        observacoesTecnicas: [
          "NĂŁo foi possĂ­vel interpretar a resposta do Supervisor como JSON.",
          String(secondError.message || secondError)
        ],
        analisadoEm: new Date()
      };
    }
  }
}

async function runSupervisor({
  lead = {},
  history = [],
  lastUserText = "",
  lastSdrText = ""
} = {}) {
  await recordAuditEvent({
    component: "gpt_supervisor",
    eventType: "supervisor_invocado",
    severity: "low",
    userPhone: lead?.user || null,
    payload: {
      contexto: "pre_resposta",
      fase: lead?.faseQualificacao || lead?.fase || null,
      temperatura: lead?.temperaturaComercial || null
    }
  });

  const recentHistory = Array.isArray(history)
    ? history.slice(-12).map(message => ({
        role: message.role,
        content: message.content
      }))
    : [];

  const supervisorPayload = {
    lead: {
      user: lead.user || "",
      status: lead.status || "",
      faseQualificacao: lead.faseQualificacao || "",
      statusOperacional: lead.statusOperacional || "",
      faseFunil: lead.faseFunil || "",
      temperaturaComercial: lead.temperaturaComercial || "",
      rotaComercial: lead.rotaComercial || "",
      origemConversao: lead.origemConversao || "",
      interesseReal: lead.interesseReal === true,
      interesseAfiliado: lead.interesseAfiliado === true,
      dadosConfirmadosPeloLead: lead.dadosConfirmadosPeloLead === true,
      crmEnviado: lead.crmEnviado === true,
      etapas: lead.etapas || {}
    },
    ultimaMensagemLead: lastUserText || "",
    ultimaRespostaSdr: lastSdrText || "",
    historicoRecente: recentHistory
  };

  const response = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      model: process.env.OPENAI_SUPERVISOR_MODEL || process.env.OPENAI_MODEL || "gpt-4o-mini",
      temperature: 0.1,
      response_format: { type: "json_object" },
      messages: [
        {
          role: "system",
          content: SUPERVISOR_SYSTEM_PROMPT
        },
        {
          role: "user",
          content: JSON.stringify(supervisorPayload)
        }
      ]
    })
  });

  const data = await response.json();

  if (!response.ok) {
    console.error("Erro ao rodar Supervisor:", data);

    await recordAuditEvent({
      component: "gpt_supervisor",
      eventType: "supervisor_abortado",
      severity: "low",
      userPhone: lead?.user || null,
      payload: { motivo: "response_not_ok" }
    });

    return {
      ...buildDefaultSupervisorAnalysis(),
      houveErroSdr: true,
      errosDetectados: ["erro_api_supervisor"],
      descricaoErroPrincipal: "Falha ao chamar a OpenAI para anĂĄlise do Supervisor.",
      riscoPerda: "nao_analisado",
      qualidadeConducaoSdr: "nao_analisado",
      observacoesTecnicas: [
        "Erro na chamada OpenAI do Supervisor.",
        JSON.stringify(data)
      ],
      analisadoEm: new Date()
    };
  }

  const rawText = data.choices?.[0]?.message?.content || "";
  const resultado = parseSupervisorJson(rawText);

  await recordAuditEvent({
    component: "gpt_supervisor",
    eventType: "supervisor_concluido",
    severity: "low",
    userPhone: lead?.user || null,
    payload: {
      riscoPerda: resultado?.riscoPerda || null,
      necessitaHumano: !!resultado?.necessitaHumano,
      prioridadeHumana: resultado?.prioridadeHumana || null,
      pontoTrava: resultado?.pontoTrava || null,
      motivoRisco: resultado?.motivoRisco || null,
      qualidadeConducaoSdr: resultado?.qualidadeConducaoSdr || null,
      notaConducaoSdr: resultado?.notaConducaoSdr || null,
      resumoDiagnostico: typeof resultado?.resumoDiagnostico === "string"
        ? resultado.resumoDiagnostico.slice(0, 300)
        : null,
      descricaoErroPrincipal: typeof resultado?.descricaoErroPrincipal === "string"
        ? resultado.descricaoErroPrincipal.slice(0, 200)
        : null,
      errosDetectadosCount: Array.isArray(resultado?.errosDetectados)
        ? resultado.errosDetectados.length
        : 0
    }
  });

  return resultado;
}

