/*
  Bug 5 â revalidaĂ§ĂŁo dos crĂ­ticos estruturais apĂłs regeneraĂ§ĂŁo.

  Roda subset de detectores que dependem da respostaFinal (texto da SDR),
  permitindo confirmar se a regeneraĂ§ĂŁo realmente eliminou os crĂ­ticos
  detectados antes do gate.

  ExcluĂ­mos do subset:
  - "continuidade_semantica_deve_ser_respeitada" â depende do analyzer de
    continuidade do lead, nĂŁo da respostaFinal; rerodar seria caro e nĂŁo
    mudaria resultado.
  - findings ALTA/MĂDIA (loop_resposta_repetida, repeticao_de_tema,
    repeticao_objecao_taxa, resposta_generica_ou_fraca,
    tentativa_reiniciar_funil, material_ja_enviado) â impacto menor,
    nĂŁo justificam nova tentativa de regeneraĂ§ĂŁo custosa.

  Todos os 8 detectores aqui foram verificados como puros (nĂŁo escrevem
  em banco, nĂŁo disparam audit_events internos). Reusam funĂ§Ă”es
  existentes sem efeito colateral.

  ATENĂĂO: runFinalRouteMixGuard Ă© async e faz fetch para OpenAI. Cada
  chamada desta funĂ§ĂŁo adiciona ~2-3s de latĂȘncia. O loop limita a
  MAX_REGEN_ATTEMPTS=2 para nĂŁo estourar custo nem latĂȘncia.
*/
async function revalidarCriticosEstruturais({
  respostaFinal,
  currentLead,
  leadText,
  history,
  preSdrConsultantAdvice,
  semanticIntent,
  commercialRouteDecision,
  taxPhaseDecision,
  podeIniciarColeta,
  coletaLiberadaPorTaxaAceita,
  turnPolicy
}) {
  const criticos = [];

  const respostaLower = String(respostaFinal || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  // 1. taxa_aceita_nao_repetir_iniciar_coleta
  if (
    taxPhaseDecision?.acao === "LIBERAR_PRE_CADASTRO" &&
    canStartDataCollection(currentLead || {}) === true
  ) {
    const respostaNormalizada = normalizeTaxDecisionText(respostaFinal || "");
    const respostaRepetiuTaxa =
      /\b(taxa|1990|1\.990|r\$ ?1\.990|investimento|adesao|adesĂŁo|implantacao|implantaĂ§ĂŁo)\b/i.test(respostaNormalizada);
    const respostaPediuNome =
      respostaNormalizada.includes("nome completo") ||
      respostaNormalizada.includes("me envie seu nome") ||
      respostaNormalizada.includes("pode me enviar seu nome");

    if (respostaRepetiuTaxa || !respostaPediuNome) {
      criticos.push({
        tipo: "taxa_aceita_nao_repetir_iniciar_coleta",
        prioridade: "critica",
        orientacao: "Lead aceitou taxa; nĂŁo repetir tema; iniciar coleta pedindo apenas nome completo."
      });
    }
  }

  // 2. pre_analise_prematura
  const mencionouPreAnalise = /pre[-\s]?analise|prĂ©[-\s]?anĂĄlise/i.test(respostaFinal);
  if (mencionouPreAnalise && !podeIniciarColeta && !coletaLiberadaPorTaxaAceita) {
    criticos.push({
      tipo: "pre_analise_prematura",
      prioridade: "critica",
      orientacao: "NĂŁo prometer prĂ©-anĂĄlise antes do backend liberar coleta."
    });
  }

  // 3. coleta_prematura
  const startedDataCollectionAgora =
    respostaLower.includes("primeiro, pode me enviar seu nome completo") ||
    respostaLower.includes("pode me enviar seu nome completo") ||
    respostaLower.includes("me envie seu nome completo") ||
    respostaLower.includes("qual seu nome completo") ||
    respostaLower.includes("me passa seu nome completo");

  if (startedDataCollectionAgora && !podeIniciarColeta && !coletaLiberadaPorTaxaAceita) {
    criticos.push({
      tipo: "coleta_prematura",
      prioridade: "critica",
      orientacao: "NĂŁo iniciar coleta antes do backend liberar; conduzir para etapa pendente do funil."
    });
  }

  // 4. pedido_multiplos_dados
  const multiDataRequestPattern =
    /nome.*cpf.*telefone.*cidade|cpf.*nome.*telefone|telefone.*cpf.*cidade/i;
  if (multiDataRequestPattern.test(respostaFinal)) {
    criticos.push({
      tipo: "pedido_multiplos_dados",
      prioridade: "critica",
      orientacao: "Pedir apenas UM dado por vez, comeĂ§ando pelo nome completo."
    });
  }

  // 5. contradicao_orientacao_pre_sdr
  const consultantGuard = enforceConsultantDirectionOnFinalReply({
    respostaFinal,
    consultantAdvice: preSdrConsultantAdvice || {},
    currentLead,
    leadText
  });
  if (consultantGuard.changed) {
    criticos.push({
      tipo: "contradicao_orientacao_pre_sdr",
      prioridade: "critica",
      reason: consultantGuard.reason,
      orientacao: "A resposta contradiz a orientaĂ§ĂŁo do Consultor PrĂ©-SDR."
    });
  }

  // 6. pergunta_ou_objecao_nao_respondida
  const unansweredGuard = enforceLeadQuestionWasAnswered({
    leadText,
    respostaFinal,
    currentLead
  });
  if (unansweredGuard.changed) {
    const originalMissingThemes = Array.isArray(unansweredGuard.reason?.missingThemes)
      ? unansweredGuard.reason.missingThemes
      : [];
    const filteredMissingThemes = iqgFilterMissingThemesAlreadyUnderstood({
      leadText,
      missingThemes: originalMissingThemes
    });
    const deveIgnorar =
      originalMissingThemes.length > 0 &&
      filteredMissingThemes.length === 0;

    if (!deveIgnorar) {
      criticos.push({
        tipo: "pergunta_ou_objecao_nao_respondida",
        prioridade: "critica",
        reason: unansweredGuard.reason,
        orientacao: "Responder primeiro a pergunta/objeĂ§ĂŁo real do lead."
      });
    }
  }

  // 7. disciplina_funil (enforceFunnelDiscipline)
  const disciplinaFunil = enforceFunnelDiscipline({
    respostaFinal,
    currentLead,
    leadText
  });
  if (disciplinaFunil.changed) {
    criticos.push({
      tipo: "disciplina_funil",
      prioridade: "critica",
      reason: disciplinaFunil.reason,
      orientacao: "NĂŁo falar taxa cedo, nĂŁo pedir dados antes da hora, nĂŁo pular fase."
    });
  }

  // 8. mistura_afiliado_homologado (async â chamada OpenAI)
  const routeMixGuard = await runFinalRouteMixGuard({
    lead: currentLead || {},
    leadText,
    respostaFinal,
    semanticIntent,
    commercialRouteDecision
  });
  if (routeMixGuard.changed) {
    criticos.push({
      tipo: "mistura_afiliado_homologado",
      prioridade: "critica",
      motivo: routeMixGuard.motivo || "",
      orientacao: "NĂŁo misturar Afiliado e Homologado na mesma resposta."
    });
  }

  // F6.2-C1: re-check de qualificaĂ§ĂŁo apĂłs regeneraĂ§ĂŁo (convergĂȘncia do loop)
  if (
    turnPolicy?.podeFalarTaxa === true &&
    /(?:1[\.,]?990|taxa de ades[ĂŁa]o|taxa de implanta[Ă§c][ĂŁa]o)/i.test(respostaFinal || "") &&
    !currentLead?.taxaQualificacaoFeitaEm &&
    !detectarOrcamentoEspontaneo(history)
  ) {
    criticos.push({
      tipo: "qualificacao_taxa_omitida",
      prioridade: "critica",
      orientacao: "Antes de apresentar R$1.990 (ou qualquer menĂ§ĂŁo Ă  taxa), faĂ§a 1 pergunta calibrada de orĂ§amento. Use uma destas variantes: (1) 'Antes de te passar o valor, qual faixa de investimento faz sentido pra vocĂȘ nesse tipo de negĂłcio?' (2) 'Antes de entrar no valor, queria entender: vocĂȘ jĂĄ pensou em alguma faixa de investimento que faria sentido pra esse tipo de oportunidade?' (3) 'Faz sentido eu te perguntar antes: vocĂȘ tem alguma faixa de investimento em mente, ou prefere eu jĂĄ te passar os nĂșmeros pra vocĂȘ avaliar?' NĂO mencione o valor da taxa nesta resposta â qualifique primeiro."
    });
  }

  return criticos;
}

