function isSoftUnderstandingConfirmation(text = "") {
  const t = String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[.,!?]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const softPatterns = [
    /^ok$/,
    /^ok obrigado$/,
    /^ok obrigada$/,
    /^sim$/,
    /^s$/,
    /^sei sim$/,
    /^entendi$/,
    /^entendi sim$/,
    /^certo$/,
    /^ta certo$/,
    /^tĂĄ certo$/,
    /^legal$/,
    /^show$/,
    /^beleza$/,
    /^blz$/,
    /^perfeito$/,
    /^top$/,
    /^faz sentido$/,
    /^fez sentido$/,
    /^fez sentido sim$/,
    /^faz sentido sim$/,
    /^foi bem explicativo$/,
    /^foi bem explicado$/,
    /^ficou claro$/,
    /^ficou claro sim$/,
    /^esta claro$/,
    /^estĂĄ claro$/
  ];

  return softPatterns.some(pattern => pattern.test(t));
}

function isExplicitPreAnalysisIntent(text = "") {
  const t = String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();

  if (isCadastroOuParticipacaoIntent(text)) {
    return true;
  }
   
  const patterns = [
    /^quero seguir$/,
    /^quero continuar$/,
    /^quero avancar$/,
    /^quero avanĂ§ar$/,
    /^podemos seguir$/,
    /^podemos avancar$/,
    /^podemos avanĂ§ar$/,
    /^pode seguir$/,
    /^pode continuar$/,
    /^pode avancar$/,
    /^pode avanĂ§ar$/,
    /^vamos seguir$/,
    /^vamos avancar$/,
    /^vamos avanĂ§ar$/,
    /^bora seguir$/,
    /^bora$/,
    /^bora la$/,
    /^bora lĂĄ$/,
    /^sim, pode seguir$/,
    /^sim pode seguir$/,
    /^sim, vamos seguir$/,
    /^sim vamos seguir$/,
    /^claro$/,
    /^claro que sim$/,
    /^com certeza$/,
    /^tenho interesse$/,
    /^tenho interesse sim$/,
    /^quero participar$/,
    /^quero entrar$/,
    /^quero fazer a pre analise$/,
    /^quero fazer a prĂ© anĂĄlise$/,
    /^quero fazer a pre-analise$/,
    /^quero fazer a prĂ©-anĂĄlise$/,
    /^pode iniciar$/,
    /^inicia$/,
    /^iniciar$/,
    /^vamos nessa$/,

    // expressĂ”es naturais de WhatsApp
    /^mete bala$/,
    /^manda ver$/,
    /^manda bala$/,
    /^demorou$/,
    /^fechou$/,
    /^fechado$/,
    /^toca ficha$/,
    /^segue$/,
    /^segue ai$/,
    /^segue aĂ­$/,
    /^vai em frente$/,
    /^pode tocar$/,
    /^pode mandar$/,
    /^manda$/,
    /^partiu$/,
    /^show, pode seguir$/,
    /^show pode seguir$/,
    /^top, pode seguir$/,
    /^top pode seguir$/
  ];

  return patterns.some(pattern => pattern.test(t));
}

function mentionsPaymentIntent(text = "") {
  const t = String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();

  return (
    t.includes("pagamento") ||
    t.includes("pagar") ||
    t.includes("pix") ||
    t.includes("cartao") ||
    t.includes("cartĂŁo") ||
    t.includes("boleto") ||
    t.includes("transferencia") ||
    t.includes("transferĂȘncia") ||
    t.includes("como pago") ||
    t.includes("quero pagar") ||
    t.includes("ja quero pagar") ||
    t.includes("jĂĄ quero pagar")
  );
}

