/* =========================
   TRAVAS FINAIS â LEITURA SEMĂNTICA LEVE
   Evita revisĂŁo desnecessĂĄria quando a SDR respondeu corretamente.
========================= */

function iqgNormalizeGuardText(value = "") {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s?]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function iqgLeadAskedToUnderstandHomologado(leadText = "") {
  const t = iqgNormalizeGuardText(leadText);

  return Boolean(
    /\b(tenho interesse|quero saber mais|quero entender|quero entender melhor|me explica|me conte|como funciona|programa|programa homologado|parceiro homologado|homologado|quero ser parceiro|quero participar|como me cadastro|como faco cadastro|como faĂ§o cadastro)\b/i.test(t)
  );
}

function iqgReplyIsSafeHomologadoOverview(respostaFinal = "") {
  const r = iqgNormalizeGuardText(respostaFinal);

  const falaHomologado =
    /\b(programa|parceiro homologado|homologado|parceria comercial|vender produtos|vender produtos da industria|vender produtos diretamente da industria)\b/i.test(r);

  const falaValorInicial =
    /\b(suporte|treinamento|materiais|material|comodato|estoque em comodato|lote inicial|pronta entrega|demonstraĂ§ĂŁo|demonstracao|beneficios|benefĂ­cios)\b/i.test(r);

  const falaTaxa =
    /\b(taxa|investimento|valor de adesao|valor de adesĂŁo|r 1 990|1990|pagamento|pix|cartao|cartĂŁo|parcelado|10x)\b/i.test(r);

  const pedeDados =
    /\b(nome completo|cpf|telefone|cidade|estado|uf|dados|pre cadastro|prĂ© cadastro|pre analise|prĂ© analise|pre analise|prĂ© anĂĄlise)\b/i.test(r);

  const falaAfiliado =
    /\b(afiliado|afiliados|link de afiliado|minhaiqg|comissao por link|comissĂŁo por link)\b/i.test(r);

  return Boolean(
    falaHomologado &&
    falaValorInicial &&
    !falaTaxa &&
    !pedeDados &&
    !falaAfiliado
  );
}

function iqgLeadSaidThemeAlreadyUnderstood(leadText = "", theme = "") {
  const t = iqgNormalizeGuardText(leadText);

  const saidUnderstood =
    /\b(ja entendi|jĂĄ entendi|entendi bem|entendi|ficou claro|ta claro|tĂĄ claro|compreendi|li no folder|pelo folder|ja li|jĂĄ li|ja vi|jĂĄ vi|vi no folder)\b/i.test(t);

  if (!saidUnderstood) return false;

  if (theme === "beneficios" || theme === "benefĂ­cios") {
    return /\b(beneficio|beneficios|benefĂ­cio|benefĂ­cios|vantagem|vantagens|folder)\b/i.test(t);
  }

  if (theme === "programa") {
    return /\b(programa|homologado|parceiro homologado|modelo)\b/i.test(t);
  }

  if (theme === "estoque") {
    return /\b(estoque|comodato|lote|kit|produtos|produto)\b/i.test(t);
  }

  if (theme === "responsabilidades") {
    return /\b(responsabilidade|responsabilidades|minha parte|obrigacao|obrigaĂ§ĂŁo|obrigacoes|obrigaĂ§Ă”es)\b/i.test(t);
  }

  return false;
}

function iqgFilterMissingThemesAlreadyUnderstood({
  leadText = "",
  missingThemes = []
} = {}) {
  const safeThemes = Array.isArray(missingThemes) ? missingThemes : [];

  return safeThemes.filter(theme => {
    const cleanTheme = iqgNormalizeGuardText(theme);

    if (cleanTheme.includes("beneficio") && iqgLeadSaidThemeAlreadyUnderstood(leadText, "beneficios")) {
      return false;
    }

    if (cleanTheme.includes("programa") && iqgLeadSaidThemeAlreadyUnderstood(leadText, "programa")) {
      return false;
    }

    if (cleanTheme.includes("estoque") && iqgLeadSaidThemeAlreadyUnderstood(leadText, "estoque")) {
      return false;
    }

    if (cleanTheme.includes("responsabilidade") && iqgLeadSaidThemeAlreadyUnderstood(leadText, "responsabilidades")) {
      return false;
    }

    return true;
  });
}

function isSafeInitialHomologadoOverviewReply({
  respostaFinal = "",
  leadText = "",
  currentLead = {}
} = {}) {
  /*
    Esta funĂ§ĂŁo evita revisĂŁo desnecessĂĄria.

    Quando o lead estĂĄ no comeĂ§o e pede para entender o Programa Homologado,
    a SDR pode dar uma visĂŁo geral curta com:
    - parceria comercial;
    - suporte;
    - treinamento;
    - material;
    - lote/estoque em comodato.

    Isso NĂO Ă© pular fase, desde que ela NĂO fale taxa, NĂO peĂ§a dados,
    NĂO prometa prĂ©-anĂĄlise e NĂO misture Afiliados.
  */

  const etapaAtual = getCurrentFunnelStage(currentLead);

  const leadPediuHomologado =
    iqgLeadAskedToUnderstandHomologado(leadText);

  const respostaSegura =
    iqgReplyIsSafeHomologadoOverview(respostaFinal);

  return Boolean(
    etapaAtual <= 2 &&
    leadPediuHomologado &&
    respostaSegura
  );
}

function enforceFunnelDiscipline({
  respostaFinal = "",
  currentLead = {},
  leadText = ""
} = {}) {
  /*
    Trava de disciplina do funil.

    O objetivo desta trava NĂO Ă© engessar a SDR.
    Ela deve bloquear somente riscos reais:
    - falar taxa cedo;
    - falar pagamento cedo;
    - pedir dados cedo;
    - mandar para prĂ©-anĂĄlise antes da hora.

    Ela NĂO deve bloquear uma explicaĂ§ĂŁo Ăștil quando o lead fez uma pergunta real.
    Exemplo permitido:
    Lead: "Quero entender melhor o programa"
    SDR: explica parceria, suporte, treinamento e comodato, sem taxa e sem dados.

    Exemplo permitido:
    Lead: "Tenho dĂșvida sobre estoque"
    SDR: explica estoque/comodato, sem taxa e sem dados.
  */

  const etapaAtual = getCurrentFunnelStage(currentLead);
  const etapaDetectadaNaResposta = detectStageFromSdrReply(respostaFinal);

  const falaDeInvestimento = replyMentionsInvestment(respostaFinal);
  const pedeDadosPessoais = replyAsksPersonalData(respostaFinal);
  const podeColetarDados = canStartDataCollection(currentLead);

  const leadTemPerguntaOuObjecao = isLeadQuestionObjectionOrCorrection(leadText);

  const tentouPularFase =
    etapaDetectadaNaResposta > 0 &&
    etapaDetectadaNaResposta > etapaAtual;

  const falouTaxaCedo =
    falaDeInvestimento &&
    etapaAtual < 5;

  const falouTaxaSemControle =
    falaDeInvestimento &&
    etapaAtual === 5;

  const pediuDadosCedo =
    pedeDadosPessoais &&
    (!podeColetarDados || leadTemPerguntaOuObjecao);
   
  const visaoGeralInicialHomologadoSegura =
    isSafeInitialHomologadoOverviewReply({
      respostaFinal,
      leadText,
      currentLead
    });

  /*
    CASO 1 â VisĂŁo geral segura do Homologado.

    Se o lead pediu para entender o Programa Parceiro Homologado,
    a SDR pode citar parceria, suporte, treinamento, materiais,
    benefĂ­cios e estoque em comodato.

    Isso NĂO Ă© pulo de fase, desde que ela nĂŁo fale taxa,
    nĂŁo peĂ§a dados e nĂŁo jogue para prĂ©-anĂĄlise.
  */
  if (
    tentouPularFase &&
    visaoGeralInicialHomologadoSegura &&
    !falouTaxaCedo &&
    !falouTaxaSemControle &&
    !pediuDadosCedo
  ) {
    return {
      changed: false,
      respostaFinal,
      reason: {
        etapaAtual,
        etapaDetectadaNaResposta,
        tentouPularFase,
        falouTaxaCedo,
        falouTaxaSemControle,
        pediuDadosCedo,
        leadTemPerguntaOuObjecao,
        preservadoPorqueVisaoGeralHomologado: true
      }
    };
  }

  /*
    CASO 2 â Lead fez pergunta real.

    Se o lead perguntou sobre estoque, benefĂ­cios, programa,
    responsabilidades ou outro ponto comercial,
    a SDR deve responder primeiro a pergunta real.

    A trava nĂŁo deve mandar revisar sĂł porque a resposta mencionou
    um tema de uma etapa diferente.

    Continuamos bloqueando taxa cedo e dados cedo.
  */
  if (
    tentouPularFase &&
    leadTemPerguntaOuObjecao &&
    !pediuDadosCedo &&
    !falouTaxaCedo &&
    !falouTaxaSemControle
  ) {
    return {
      changed: false,
      respostaFinal,
      reason: {
        etapaAtual,
        etapaDetectadaNaResposta,
        tentouPularFase,
        falouTaxaCedo,
        falouTaxaSemControle,
        pediuDadosCedo,
        leadTemPerguntaOuObjecao,
        preservadoPorqueRespondePerguntaAtual: true
      }
    };
  }

  /*
    CASO 3 â Bloqueios realmente crĂ­ticos.

    Estes continuam sendo problema:
    - taxa cedo;
    - taxa sem controle;
    - pedido de dados antes da coleta estar liberada.
  */
  if (
    falouTaxaCedo ||
    falouTaxaSemControle ||
    pediuDadosCedo
  ) {
    return {
      changed: true,
      respostaFinal,
      reason: {
        etapaAtual,
        etapaDetectadaNaResposta,
        tentouPularFase,
        falouTaxaCedo,
        falouTaxaSemControle,
        pediuDadosCedo,
        leadTemPerguntaOuObjecao
      }
    };
  }

  /*
    CASO 4 â Pulo de fase real.

    Se nĂŁo era resposta a pergunta do lead,
    nĂŁo era visĂŁo geral segura,
    e mesmo assim a resposta pulou etapa,
    aĂ­ sim a revisĂŁo deve acontecer.
  */
  if (tentouPularFase) {
    return {
      changed: true,
      respostaFinal,
      reason: {
        etapaAtual,
        etapaDetectadaNaResposta,
        tentouPularFase,
        falouTaxaCedo,
        falouTaxaSemControle,
        pediuDadosCedo,
        leadTemPerguntaOuObjecao
      }
    };
  }

  /*
    Sem problema detectado.
  */
  return {
    changed: false,
    respostaFinal,
    reason: {
      etapaAtual,
      etapaDetectadaNaResposta,
      tentouPularFase,
      falouTaxaCedo,
      falouTaxaSemControle,
      pediuDadosCedo,
      leadTemPerguntaOuObjecao
    }
  };
}

// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
// F6.2-C1: Guard de qualificaĂ§ĂŁo financeira antes da taxa.
// PadrĂŁo return + caller dĂĄ push (consistĂȘncia com enforceFunnelDiscipline).
// 4 gates (todos true pra empurrar finding):
//   1. turnPolicy.podeFalarTaxa === true (nĂŁo duplica enforceFunnelDiscipline)
//   2. Resposta menciona R$1.990 / taxa de adesĂŁo / taxa de implantaĂ§ĂŁo
//   3. lead.taxaQualificacaoFeitaEm NĂO setado
//   4. history sem menĂ§ĂŁo espontĂąnea de orĂ§amento
// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
function enforceQualificacaoTaxaPrimeiro({ respostaFinal, currentLead, history, turnPolicy } = {}) {
  if (turnPolicy?.podeFalarTaxa !== true) {
    return { changed: false, reason: "podeFalarTaxa_false_ou_undefined" };
  }

  const REGEX_TAXA_NA_RESPOSTA = /(?:1[\.,]?990|taxa de ades[ĂŁa]o|taxa de implanta[Ă§c][ĂŁa]o)/i;
  if (!REGEX_TAXA_NA_RESPOSTA.test(respostaFinal || "")) {
    return { changed: false, reason: "taxa_nao_apresentada" };
  }

  if (currentLead?.taxaQualificacaoFeitaEm) {
    return { changed: false, reason: "lead_ja_qualificado" };
  }

  if (detectarOrcamentoEspontaneo(history)) {
    return { changed: false, reason: "orcamento_espontaneo_detectado" };
  }

  const finding = {
    tipo: "qualificacao_taxa_omitida",
    prioridade: "critica",
    orientacao: "Antes de apresentar R$1.990 (ou qualquer menĂ§ĂŁo Ă  taxa), faĂ§a 1 pergunta calibrada de orĂ§amento. Use uma destas variantes: (1) 'Antes de te passar o valor, qual faixa de investimento faz sentido pra vocĂȘ nesse tipo de negĂłcio?' (2) 'Antes de entrar no valor, queria entender: vocĂȘ jĂĄ pensou em alguma faixa de investimento que faria sentido pra esse tipo de oportunidade?' (3) 'Faz sentido eu te perguntar antes: vocĂȘ tem alguma faixa de investimento em mente, ou prefere eu jĂĄ te passar os nĂșmeros pra vocĂȘ avaliar?' NĂO mencione o valor da taxa nesta resposta â qualifique primeiro."
  };

  return { changed: true, reason: "qualificacao_taxa_omitida", finding };
}

// F7.2a â Guard de qualificaĂ§ĂŁo inicial (Bug A).
// Detecta pergunta genĂ©rica proibida na 1ÂȘ resposta da SDR (gate: assistantMsgs===0).
// Tipo descartĂĄvel: se regen falhar, Ă© melhoria de conduĂ§ĂŁo (nĂŁo perigo) â manda mesmo assim.
function enforceQualificacaoInicial({ respostaFinal, history } = {}) {
  const assistantMsgs = (history || []).filter(m => m?.role === "assistant").length;
  if (assistantMsgs !== 0) {
    return { changed: false, reason: "not_first_response" };
  }

  const resposta = (respostaFinal || "").toLowerCase();
  const PROIBIDAS = [
    /quer entender como funciona( na pr[ĂĄa]tica)?\??/i,
    /ficou alguma d[Ășu]vida/i,
    /tem (mais|alguma) (perguntas?|d[Ășu]vidas?)/i,
    /alguma outra coisa/i,
    /tem algum ponto que.*(saber|discutir)/i,
    /alguma d[Ășu]vida ou ponto/i
  ];

  const padraoDetectado = PROIBIDAS.find(re => re.test(resposta));
  if (!padraoDetectado) {
    return { changed: false, reason: "qualificacao_ok" };
  }

  return {
    changed: true,
    reason: "qualificacao_inicial_omitida",
    finding: {
      tipo: "qualificacao_inicial_omitida",
      prioridade: "critica",
      orientacao: "Esta Ă© a primeira resposta ao lead. PROIBIDO terminar com pergunta genĂ©rica ('quer entender', 'ficou dĂșvida', 'tem dĂșvida', 'tem algum ponto'). OBRIGATĂRIO terminar com pergunta de QUALIFICAĂĂO calibrada (vocĂȘ jĂĄ atua com piscina? o que mais te chamou atenĂ§ĂŁo? vocĂȘ jĂĄ vende algum produto quĂ­mico hoje?). Aplicar REGRA 2 SPIN do PrĂ©-SDR."
    }
  };
}

function getLastAssistantMessage(history = []) {
  if (!Array.isArray(history)) return "";

  for (let i = history.length - 1; i >= 0; i--) {
    if (history[i]?.role === "assistant") {
      return history[i]?.content || "";
    }
  }

  return "";
}

function isShortNeutralLeadReply(text = "") {
  const t = normalizeCommercialText(text);

  if (!t) return false;
  if (t.length > 45) return false;

  const neutralPatterns = [
    /^ok$/,
    /^ok obrigado$/,
    /^ok obrigada$/,
    /^sim$/,
    /^s$/,
    /^certo$/,
    /^ta certo$/,
    /^tĂĄ certo$/,
    /^entendi$/,
    /^entendi sim$/,
    /^legal$/,
    /^show$/,
    /^show de bola$/,
    /^beleza$/,
    /^blz$/,
    /^perfeito$/,
    /^top$/,
    /^aham$/,
    /^uhum$/,
    /^faz sentido$/,
    /^fez sentido$/,
    /^para mim faz sentido$/,
    /^pra mim faz sentido$/,
    /^combinado$/,
    /^tranquilo$/,
    /^ta bom$/,
    /^tĂĄ bom$/
  ];

  return neutralPatterns.some(pattern => pattern.test(t));
}

/*
  Bug fechamento conversacional â detecĂ§ĂŁo determinĂ­stica.
  Combina 3 sinais (lead curto + SDR longa + bordĂŁo muleta na SDR).
  Conservador: precisa dos 3 simultĂąneos pra disparar â falso positivo
  Ă© improvĂĄvel. Usado pelo bypass de fechamento (antes do gate de
  regeneraĂ§ĂŁo) que substitui a resposta por fallback contextual curto.
*/
const FECHAMENTO_BORDAO_PATTERNS = [
  /estou (?:Ă  |a )?disposi[Ă§c][ĂŁa]o/i,
  /fico (?:Ă  |a )?disposi[Ă§c][ĂŁa]o/i,
  /estou (?:aqui |sempre )?(?:para |pra )?(?:te )?ajudar/i,
  /estarei aqui/i,
  /fique (?:a |Ă  )vontade/i,
  /(?:^|\s)se precisar/i,
  /qualquer d[Ășu]vida/i,
  /qualquer coisa/i,
  /qualquer momento/i,
  /(?:Ă© )?s[Ăło] me (?:chamar|avisar|mandar)/i,
  /n[ĂŁa]o hesite/i,
  /retomar (?:a |nossa )?conversa/i,
  /quando (?:voc[ĂȘe] )?(?:puder|voltar|estiver|quiser|tiver)/i,
  /quando estiver pronto/i,
  /estou por aqui/i
];

function detectFechamentoConversacionalParedao(leadText = "", sdrText = "") {
  const lead = String(leadText || "").trim();
  const sdr = String(sdrText || "").trim();

  if (lead.length < 1 || lead.length > 25) return false;
  if (sdr.length <= 100) return false;

  // Fechamento NUNCA Ă© pergunta. Excluir interrogativas para nĂŁo trocar
  // resposta legĂ­tima por fallback curto (bug: "CadĂȘ a tabela?" -> "đ").
  if (lead.endsWith("?")) return false;
  if (/\b(cad[ĂȘe]|qual|quais|quanto|quantos|quanta|quantas|onde|como|quando|porqu|por que|porque|preciso|precisa|posso|pode|tem que|d[ĂĄa] pra|funciona)\b/i.test(lead)) return false;

  return FECHAMENTO_BORDAO_PATTERNS.some(re => re.test(sdr));
}

/*
  Fallback contextual curto quando o bypass de fechamento dispara.
  Hierarquia de match (primeira que casar vence):
    1. Lead sĂł emojis -> espelha o emoji
    2. Lead agradece (amĂ©m/gratidĂŁo/obrigado/valeu) -> espelha com nome
    3. Lead pausa (depois/amanhĂŁ/viagem/reuniĂŁo/etc) -> "Combinado, [Nome]. Quando puder a gente continua."
    4. Lead ack curto (ok/sim/show/top/etc) -> "Combinado!"
    5. Default -> null (nĂŁo classificĂĄvel como fechamento real;
       sinaliza ao caller para NĂO aplicar o bypass e manter a resposta original).
*/
function buildClosureSafeFallback(leadText = "", currentLead = {}) {
  const lead = String(leadText || "").trim();
  const nome = getFirstName(currentLead?.nome || currentLead?.nomeWhatsApp || "");

  // 1. SĂł emojis
  if (lead.length > 0 && /^[\p{Extended_Pictographic}\s]+$/u.test(lead)) {
    return lead;
  }

  // 2. Agradecimento
  if (/^(am[Ă©e]m|gratid[ĂŁa]o|obrigad[oa]|valeu)/i.test(lead)) {
    return nome ? `${lead}, ${nome}!` : `${lead}!`;
  }

  // 3. Pausa
  if (/(depois|amanh[ĂŁa]|outra hora|estou viajando|em viagem|sem tempo|em reuni[ĂŁa]o|vou pensar|vou olhar)/i.test(lead)) {
    return nome
      ? `Combinado, ${nome}. Quando puder a gente continua.`
      : "Combinado. Quando puder a gente continua.";
  }

  // 4. Ack curto
  if (/^(ok|sim|certo|entendi|show|top|fez sentido|ficou claro|tudo bem|beleza)\.?!?$/i.test(lead)) {
    return "Combinado!";
  }

  // 5. Default â nĂŁo classificĂĄvel como fechamento real.
  // Retorna null: o caller mantĂ©m a resposta original (nĂŁo aplica bypass).
  return null;
}

function detectReplyMainTheme(text = "") {
  const t = normalizeCommercialText(text);

  if (!t) return "";

  if (
    t.includes("afiliado") ||
    t.includes("link exclusivo") ||
    t.includes("divulgar por link") ||
    t.includes("comissao online") ||
    t.includes("comissĂŁo online")
  ) {
    return "afiliado";
  }

  if (
    replyAsksPersonalData(text) ||
    t.includes("pre-analise") ||
    t.includes("pre analise") ||
    t.includes("prĂ©-anĂĄlise") ||
    t.includes("preanalise")
  ) {
    return "coleta";
  }

  if (
    t.includes("resultado depende") ||
    t.includes("depende da sua atuacao") ||
    t.includes("depende da sua atuaĂ§ĂŁo") ||
    t.includes("atuacao nas vendas") ||
    t.includes("atuaĂ§ĂŁo nas vendas")
  ) {
    return "compromisso";
  }

  if (replyMentionsInvestment(text)) {
    return "investimento";
  }

  if (
    t.includes("responsabilidade") ||
    t.includes("responsabilidades") ||
    t.includes("guarda") ||
    t.includes("conservacao") ||
    t.includes("conservaĂ§ĂŁo") ||
    t.includes("comunicacao correta") ||
    t.includes("comunicaĂ§ĂŁo correta")
  ) {
    return "responsabilidades";
  }

  if (
    t.includes("estoque") ||
    t.includes("comodato") ||
    t.includes("lote inicial") ||
    t.includes("kit inicial") ||
    t.includes("pronta-entrega") ||
    t.includes("pronta entrega")
  ) {
    return "estoque";
  }

  if (
    t.includes("beneficio") ||
    t.includes("benefĂ­cios") ||
    t.includes("beneficios") ||
    t.includes("suporte") ||
    t.includes("treinamento") ||
    t.includes("materiais")
  ) {
    return "beneficios";
  }
   
  if (
    t.includes("programa") ||
    t.includes("parceria") ||
    t.includes("parceiro homologado") ||
    t.includes("como funciona")
  ) {
    return "programa";
  }

  return "";
}

