function removeFileAction(actions = [], keyToRemove = "") {
  if (!Array.isArray(actions)) return;

  for (let i = actions.length - 1; i >= 0; i--) {
    if (actions[i] === keyToRemove) {
      actions.splice(i, 1);
    }
  }
}

