async function sendFileOnce(from, key, options = {}) {
  const { forceResend = false, resendReason = null } = options;

  /*
    ETAPA 7 PRODUĂĂO â arquivo sĂł Ă© marcado como enviado depois do sucesso real.

    ExplicaĂ§ĂŁo simples:
    Antes, o sistema marcava "enviado" antes de enviar.
    Se o WhatsApp falhasse, o Mongo ficava dizendo que enviou, mas o lead nĂŁo recebia.

    Agora:
    1. tenta enviar primeiro;
    2. se der certo, marca sentFiles;
    3. se falhar, NĂO marca sentFiles;
    4. grava log do erro para auditoria.

    BUG 2 â reenvio quando lead reclama:
    Se forceResend=true (caller detectou reclamaĂ§ĂŁo tipo "nĂŁo recebi", "cadĂȘ"),
    a funĂ§ĂŁo ignora o bloqueio de "jĂĄ enviou", mas respeita o cooldown
    FILE_RESEND_COOLDOWN_MS para evitar spam por mensagens repetidas.
  */

  if (!FILES[key]) {
    console.error("â Arquivo solicitado nĂŁo existe em FILES:", {
      user: from,
      arquivo: key
    });

    await connectMongo();

    await db.collection("file_send_logs").insertOne({
      user: from,
      fileKey: key,
      status: "failed",
      reason: "file_key_not_found",
      createdAt: new Date()
    });

    return false;
  }

  await connectMongo();

  const sentField = `sentFiles.${key}`;

  const lead = await db.collection("leads").findOne({ user: from });
  const sentAt = lead?.sentFiles?.[key];

  if (sentAt && !forceResend) {
    console.log("đ Arquivo nĂŁo reenviado porque jĂĄ foi enviado:", {
      user: from,
      arquivo: key,
      enviadoEm: sentAt
    });

    await db.collection("file_send_logs").insertOne({
      user: from,
      fileKey: key,
      filename: FILES[key]?.filename || "",
      status: "skipped_already_sent",
      alreadySentAt: sentAt,
      createdAt: new Date()
    });

    return false;
  }

  if (sentAt && forceResend) {
    const ageMs = Date.now() - new Date(sentAt).getTime();

    if (ageMs < FILE_RESEND_COOLDOWN_MS) {
      console.log("đ Reenvio ignorado (cooldown anti-spam):", {
        user: from,
        arquivo: key,
        motivo: resendReason || "forced_resend_within_cooldown",
        ultimoEnvioMs: ageMs,
        cooldownMs: FILE_RESEND_COOLDOWN_MS
      });

      await db.collection("file_send_logs").insertOne({
        user: from,
        fileKey: key,
        filename: FILES[key]?.filename || "",
        status: "resend_cooldown_active",
        alreadySentAt: sentAt,
        ageMs,
        resendReason: resendReason || null,
        createdAt: new Date()
      });

      return false;
    }

    console.log("đ Reenvio de arquivo autorizado:", {
      user: from,
      arquivo: key,
      motivo: resendReason || "forced_resend",
      envioAnterior: sentAt
    });
  }

  const isResend = Boolean(sentAt && forceResend);

  try {
    await db.collection("file_send_logs").insertOne({
      user: from,
      fileKey: key,
      filename: FILES[key]?.filename || "",
      status: "started",
      isResend,
      resendReason: isResend ? resendReason : null,
      createdAt: new Date()
    });

    await delay(2000);

    const sendResult = await sendWhatsAppDocument(from, FILES[key]);

    await db.collection("leads").updateOne(
      { user: from },
      {
        $set: {
          [sentField]: new Date(),
          [`sentFileDetails.${key}`]: {
            filename: FILES[key]?.filename || "",
            mediaId: sendResult?.mediaId || "",
            messageId: sendResult?.messageId || "",
            sentAt: new Date(),
            isResend,
            resendReason: isResend ? resendReason : null
          },
          updatedAt: new Date()
        }
      },
      { upsert: true }
    );

    await db.collection("file_send_logs").insertOne({
      user: from,
      fileKey: key,
      filename: FILES[key]?.filename || "",
      status: isResend ? "resent_after_complaint" : "success",
      mediaId: sendResult?.mediaId || "",
      messageId: sendResult?.messageId || "",
      isResend,
      resendReason: isResend ? resendReason : null,
      previousSentAt: isResend ? sentAt : null,
      createdAt: new Date()
    });

    console.log(
      isResend
        ? "â Arquivo REENVIADO com sucesso apĂłs reclamaĂ§ĂŁo do lead:"
        : "â Arquivo marcado como enviado apĂłs sucesso real:",
      {
        user: from,
        arquivo: key,
        filename: FILES[key]?.filename || "",
        mediaId: sendResult?.mediaId || "",
        messageId: sendResult?.messageId || "",
        motivo: isResend ? resendReason : null
      }
    );

    return true;
  } catch (error) {
    console.error("â Falha ao enviar arquivo. NĂO serĂĄ marcado como enviado:", {
      user: from,
      arquivo: key,
      filename: FILES[key]?.filename || "",
      erro: error.message,
      tentativaReenvio: isResend
    });

    await db.collection("file_send_logs").insertOne({
      user: from,
      fileKey: key,
      filename: FILES[key]?.filename || "",
      status: "failed",
      errorMessage: error.message,
      isResend,
      resendReason: isResend ? resendReason : null,
      createdAt: new Date()
    });

    return false;
  }
}

function getBrazilNow() {
  const now = new Date();
  const utc = now.getTime() + now.getTimezoneOffset() * 60000;
  return new Date(utc + BUSINESS_TIMEZONE_OFFSET * 60 * 60 * 1000);
}

function getGreetingByBrazilTime() {
  const now = getBrazilNow();
  const hour = now.getHours();

  if (hour >= 5 && hour < 12) {
    return "bom dia";
  }

  if (hour >= 12 && hour < 18) {
    return "boa tarde";
  }

  return "boa noite";
}

/* =========================
   DETECĂĂO INTELIGENTE DE SOLICITAĂĂO DE PRAZO/HORĂRIO
   Quando o cliente pede para ser contactado depois (ex: "me chama amanhĂŁ",
   "estou ocupado", "Ă  noite te respondo"), o sistema detecta,
   pausa a cadĂȘncia e agenda o recontato.
========================= */

const SCHEDULE_REQUEST_PATTERNS = [
  // "me chama/liga/retorna" + referĂȘncia temporal
  /me\s+(chame|chama|ligue|liga|retorne|retorna|responde|responda)\s+.{0,30}(amanh[aĂŁ]|depois|pr[oĂł]xim|segunda|ter[cĂ§]a|quarta|quinta|sexta|s[aĂĄ]bado|daqui|em\s+\d+|mais\s+tarde|noite|tarde|manh[aĂŁ])/i,
  // "estou ocupado/trabalhando" + "me chama"
  /estou\s+(ocupad[oa]|trabalhando|em\s+reuni[aĂŁ]o|em\s+call|atendendo|dirigindo|no\s+trabalho|correndo).{0,60}(me\s+chame|me\s+chama|me\s+ligue|me\s+liga|me\s+retorne|me\s+retorna|retorn[ao]|depois)/i,
  // "me chama" + "estou ocupado"
  /(me\s+chame|me\s+chama|me\s+ligue|me\s+liga|me\s+retorne|me\s+retorna).{0,60}estou\s+(ocupad[oa]|trabalhando|em\s+reuni[aĂŁ]o)/i,
  // "pode ser amanhĂŁ/depois/Ă  noite"
  /pode\s+(ser|ficar\s+pra?)\s+(amanh[aĂŁ]|depois|Ă ?\s*noite|de\s+noite|mais\s+tarde|pr[oĂł]xim|segunda|ter[cĂ§]a|quarta|quinta|sexta)/i,
  // "depois de amanhĂŁ"
  /(depois|dps)\s+de\s+amanh[aĂŁ]/i,
  // "amanhĂŁ Ă  noite/de manhĂŁ"
  /amanh[aĂŁ]\s+(Ă ?\s*noite|de\s+noite|Ă ?\s*tarde|de\s+tarde|de\s+manh[aĂŁ]|cedo|cedinho)/i,
  // "Ă  noite te respondo/falo"
  /(Ă ?\s*noite|de\s+noite|mais\s+tarde|depois)\s+(te\s+respondo|te\s+falo|eu\s+respondo|eu\s+falo|a\s+gente\s+conversa|conversamos|vejo)/i,
  // "na prĂłxima segunda/semana"
  /n[ao]\s+pr[oĂł]xim[ao]\s+(segunda|ter[cĂ§]a|quarta|quinta|sexta|semana)/i,
  // "agora nĂŁo dĂĄ/posso" + tempo
  /(agora\s+n[aĂŁ]o\s+(d[aĂĄ]|posso|consigo)|n[aĂŁ]o\s+(d[aĂĄ]|posso|consigo)\s+agora).{0,40}(depois|amanh[aĂŁ]|mais\s+tarde|noite)/i,
  // "daqui X horas/dias"
  /daqui\s+(a\s+)?\d+\s*(hora|min|dia|semana)/i,
  // "me chama Ă s 19h"
  /(me\s+chame?|me\s+ligue?|retorn[ae]?).{0,30}([Ă a]s\s+)?\d{1,2}\s*(h|hora|:\d{2})/i,
  // "depois das 18h"
  /depois\s+d[ao]s?\s+\d{1,2}\s*(h|hora|:\d{2})/i,
  // "agendar/marcar conversa/ligaĂ§ĂŁo para amanhĂŁ/segunda/horĂĄrio"
  /(agendar|agenda|marcar|marca|remarcar|remarca)\s+.{0,40}(conversa|conversar|ligaĂ§ĂŁo|ligacao|call|reuni[aĂŁ]o|papo|hor[aĂĄ]rio|amanh[aĂŁ]|depois|pr[oĂł]xim|segunda|ter[cĂ§]a|quarta|quinta|sexta)/i,
  // "conversar/falar/continuar amanhĂŁ/depois/segunda"
  /(conversar|conversamos|falar|continuar|prosseguir|retomar|seguir)\s+.{0,15}(amanh[aĂŁ]|depois|mais\s+tarde|pr[oĂł]xim|outro\s+dia|outro\s+momento|segunda|ter[cĂ§]a|quarta|quinta|sexta)/i,
  // "vamos/podemos conversar/falar amanhĂŁ" (com palavra no meio)
  /(vamos|podemos|poderia|consegue|conseguimos|d[aĂĄ]\s+pra|tem\s+como|seria\s+possĂ­vel|seria\s+possivel)\s+.{0,30}(conversar|falar|agendar|marcar|continuar|retomar|seguir).{0,30}(amanh[aĂŁ]|depois|mais\s+tarde|pr[oĂł]xim|outro\s+dia|segunda|ter[cĂ§]a|quarta|quinta|sexta|\d{1,2}\s*(h|hora|:\d{2}))/i,
  // "amanhĂŁ Ă s Xh" / "segunda Ă s Xh"
  /(amanh[aĂŁ]|segunda|ter[cĂ§]a|quarta|quinta|sexta|s[aĂĄ]bado|domingo)\s+([Ă a]s\s+)?\d{1,2}\s*(h|hora|:\d{2})/i,
  // "antes de [qualquer coisa], vamos/podemos conversar/falar amanhĂŁ"
  /antes\s+de\s+.{0,40}(conversar|falar|continuar|seguir|conversamos)\s+.{0,15}(amanh[aĂŁ]|depois|mais\s+tarde|pr[oĂł]xim|outro\s+dia|segunda|ter[cĂ§]a|quarta|quinta|sexta)/i,
  // "sĂł consigo/posso amanhĂŁ/Ă  noite"
  /(sĂł|so)\s+(consigo|posso|d[aĂĄ]|tenho\s+tempo)\s+.{0,20}(amanh[aĂŁ]|depois|mais\s+tarde|noite|tarde|manh[aĂŁ]|segunda|ter[cĂ§]a|quarta|quinta|sexta)/i,
  // "vamos deixar pra amanhĂŁ/depois"
  /(vamos|bora|melhor)\s+(deixar|adiar|remarcar|empurrar)\s+.{0,20}(amanh[aĂŁ]|depois|pr[oĂł]xim|segunda|outro\s+dia|outro\s+hor[aĂĄ]rio)/i
];

function detectScheduleRequest(text) {
  if (!text || String(text).trim().length < 5) {
    return { detected: false };
  }

  const normalizedText = String(text)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  let matchedPattern = null;
  for (const pattern of SCHEDULE_REQUEST_PATTERNS) {
    if (pattern.test(text)) {
      matchedPattern = pattern.source;
      break;
    }
  }

  if (!matchedPattern) {
    return { detected: false };
  }

  const periodo = extractRequestedPeriod(normalizedText);
  const horario = extractRequestedTime(normalizedText);
  const motivacao = extractMotivation(normalizedText);

  return {
    detected: true,
    periodo,
    horario,
    motivacao,
    patternMatched: matchedPattern,
    originalText: String(text).slice(0, 200),
    detectedAt: new Date()
  };
}

function extractRequestedPeriod(text) {
  if (/depois\s*de\s*amanh[aĂŁ]|dps\s*de\s*amanh/i.test(text)) return "depois_de_amanha";
  if (/amanh[aĂŁ]/i.test(text)) return "amanha";
  if (/proxim[ao]\s*segunda|na\s*segunda/i.test(text)) return "segunda";
  if (/proxim[ao]\s*terca|na\s*terca/i.test(text)) return "terca";
  if (/proxim[ao]\s*quarta|na\s*quarta/i.test(text)) return "quarta";
  if (/proxim[ao]\s*quinta|na\s*quinta/i.test(text)) return "quinta";
  if (/proxim[ao]\s*sexta|na\s*sexta/i.test(text)) return "sexta";
  if (/proxim[ao]\s*sabado|no\s*sabado/i.test(text)) return "sabado";
  if (/proxim[ao]\s*semana/i.test(text)) return "proxima_semana";

  const matchDaqui = text.match(/daqui\s*(a\s*)?(\d+)\s*(hora|min|dia|semana)/i);
  if (matchDaqui) {
    const quantidade = parseInt(matchDaqui[2]);
    const unidade = matchDaqui[3].toLowerCase();
    if (unidade.startsWith("hora")) return `daqui_${quantidade}_horas`;
    if (unidade.startsWith("min")) return `daqui_${quantidade}_minutos`;
    if (unidade.startsWith("dia")) return `daqui_${quantidade}_dias`;
    if (unidade.startsWith("semana")) return `daqui_${quantidade}_semanas`;
  }

  if (/mais\s*tarde|depois/i.test(text)) return "mais_tarde";

  return "indefinido";
}

function extractRequestedTime(text) {
  const matchHorarioExplicito = text.match(/(\d{1,2})\s*(h|hora|:\d{2})/i);
  if (matchHorarioExplicito) {
    const hora = parseInt(matchHorarioExplicito[1]);
    if (hora >= 0 && hora <= 23) return `${hora}h`;
  }

  const matchDepoisDas = text.match(/depois\s*d[ao]s?\s*(\d{1,2})\s*(h|hora)/i);
  if (matchDepoisDas) {
    const hora = parseInt(matchDepoisDas[1]);
    if (hora >= 0 && hora <= 23) return `${hora}h`;
  }

  if (/de\s*manha|cedinho|cedo/i.test(text)) return "manha";
  if (/[aĂ ]\s*tarde|de\s*tarde/i.test(text)) return "tarde";
  if (/[aĂ ]\s*noite|de\s*noite/i.test(text)) return "noite";

  return "indefinido";
}

function extractMotivation(text) {
  if (/ocupad[oa]/i.test(text)) return "ocupado";
  if (/trabalhando|no\s*trabalho/i.test(text)) return "trabalhando";
  if (/reuni[aĂŁ]o|call/i.test(text)) return "reuniao";
  if (/dirigindo/i.test(text)) return "dirigindo";
  if (/atendendo/i.test(text)) return "atendendo";
  if (/correndo/i.test(text)) return "correndo";
  return "nenhuma";
}

/* =========================
   CĂLCULO DE DATA/HORA DO RECONTATO AGENDADO
========================= */

function computeScheduledCallbackDate(detection) {
  const agora = new Date();
  const data = new Date(agora);

  switch (detection.periodo) {
    case "amanha":
      data.setDate(data.getDate() + 1);
      break;
    case "depois_de_amanha":
      data.setDate(data.getDate() + 2);
      break;
    case "segunda":
      advanceToWeekday(data, 1);
      break;
    case "terca":
      advanceToWeekday(data, 2);
      break;
    case "quarta":
      advanceToWeekday(data, 3);
      break;
    case "quinta":
      advanceToWeekday(data, 4);
      break;
    case "sexta":
      advanceToWeekday(data, 5);
      break;
    case "sabado":
      advanceToWeekday(data, 6);
      break;
    case "proxima_semana":
      advanceToWeekday(data, 1);
      break;
    case "mais_tarde":
      data.setTime(data.getTime() + 3 * 60 * 60 * 1000);
      break;
    default:
      if (detection.periodo.startsWith("daqui_")) {
        const parts = detection.periodo.split("_");
        const quantidade = parseInt(parts[1]) || 1;
        const unidade = parts[2] || "horas";
        if (unidade === "horas") data.setTime(data.getTime() + quantidade * 60 * 60 * 1000);
        else if (unidade === "minutos") data.setTime(data.getTime() + quantidade * 60 * 1000);
        else if (unidade === "dias") data.setDate(data.getDate() + quantidade);
        else if (unidade === "semanas") data.setDate(data.getDate() + quantidade * 7);
      } else {
        data.setDate(data.getDate() + 1);
      }
      break;
  }

  if (detection.horario !== "indefinido") {
    if (detection.horario.endsWith("h")) {
      const hora = parseInt(detection.horario);
      if (!isNaN(hora) && hora >= 0 && hora <= 23) {
        data.setHours(hora, 0, 0, 0);
      }
    } else {
      switch (detection.horario) {
        case "manha":
          data.setHours(9, 0, 0, 0);
          break;
        case "tarde":
          data.setHours(14, 0, 0, 0);
          break;
        case "noite":
          data.setHours(19, 30, 0, 0);
          break;
      }
    }
  } else {
    if (data.toDateString() !== agora.toDateString()) {
      data.setHours(10, 0, 0, 0);
    }
  }

  const startHour = typeof BUSINESS_START_HOUR === "number" ? BUSINESS_START_HOUR : 8;
  const endHour = typeof BUSINESS_END_HOUR === "number" ? BUSINESS_END_HOUR : 20;

  if (data.getHours() < startHour) {
    data.setHours(startHour, 0, 0, 0);
  }
  if (data.getHours() >= endHour) {
    data.setDate(data.getDate() + 1);
    data.setHours(startHour, 0, 0, 0);
  }

  const minimoFuturo = new Date(agora.getTime() + 5 * 60 * 1000);
  if (data < minimoFuturo) {
    return minimoFuturo;
  }

  return data;
}

function advanceToWeekday(date, targetDay) {
  const currentDay = date.getDay();
  let daysToAdd = (targetDay - currentDay + 7) % 7;
  if (daysToAdd === 0) daysToAdd = 7;
  date.setDate(date.getDate() + daysToAdd);
}

function formatScheduleConfirmationMessage(detection, scheduledDate, leadName) {
  const nome = leadName ? `${leadName}, ` : "";

  const diaSemana = scheduledDate.toLocaleDateString("pt-BR", { weekday: "long" });
  const dataFormatada = scheduledDate.toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit" });
  const horaFormatada = scheduledDate.toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" });

  return `${nome}anotado! â Vou retomar nosso contato ${diaSemana} (${dataFormatada}) Ă s ${horaFormatada} como combinado. Qualquer coisa antes disso, Ă© sĂł me chamar! đ`;
}

/* =========================
   AGENDAR RECONTATO + PAUSAR CADĂNCIA
========================= */

async function scheduleClientCallback(from, lead, detection) {
  try {
    await connectMongo();

    // Se a detecĂ§ĂŁo trouxe uma data jĂĄ calculada pelo classificador GPT
    // (scheduledDateOverride), usa ela. SenĂŁo, calcula por extraĂ§ĂŁo de texto.
    let scheduledDate;
    if (detection.scheduledDateOverride instanceof Date && !isNaN(detection.scheduledDateOverride.getTime())) {
      scheduledDate = detection.scheduledDateOverride;
      console.log("đ scheduleClientCallback usando data do classificador GPT:", {
        user: from,
        scheduledDate: scheduledDate.toISOString()
      });
    } else {
      scheduledDate = computeScheduledCallbackDate(detection);
    }

    const nome = getFirstName(lead?.nomeWhatsApp || lead?.nome || "");

    // 1) Pausar cadĂȘncia
    clearTimers(from);
    await saveLeadProfile(from, {
      proximoFollowupEm: null,
      followupStep: 0,
      followupLockEm: null,
      cadenciaPausadaPorCliente: true,
      cadenciaPausadaEm: new Date(),
      cadenciaPausadaMotivo: detection.motivacao || "solicitacao_prazo",
      agendamentoRecontato: {
        dataAgendada: scheduledDate,
        periodo: detection.periodo,
        horario: detection.horario,
        mensagemOriginal: detection.originalText
      }
    });

    // 2) Criar documento de agendamento
    const agendamento = {
      user: from,
      lead_id: lead?._id || null,
      nome: nome || "",
      originalText: detection.originalText || "",
      detection: {
        periodo: detection.periodo,
        horario: detection.horario,
        motivacao: detection.motivacao,
        patternMatched: detection.patternMatched
      },
      scheduledDate: scheduledDate,
      status: "pendente",
      tentativas: 0,
      maxTentativas: 3,
      createdAt: new Date(),
      executedAt: null,
      cancelledAt: null
    };

    await db.collection("scheduled_callbacks").insertOne(agendamento);

    // 3) Enviar confirmaĂ§ĂŁo ao lead
    const confirmationMsg = formatScheduleConfirmationMessage(
      detection,
      scheduledDate,
      nome
    );

    await sendWhatsAppMessage(from, confirmationMsg);

    // 4) Salvar confirmaĂ§ĂŁo no histĂłrico
    const history = await loadConversation(from);
    history.push({
      role: "user",
      content: detection.originalText,
      createdAt: new Date(),
      origem: "lead"
    });
    history.push({
      role: "assistant",
      content: confirmationMsg,
      createdAt: new Date(),
      origem: "agendamento_confirmacao"
    });
    await saveConversation(from, history);

    // 5) Audit
    if (typeof auditSystemEvent === "function") {
      await auditSystemEvent("agendamento_recontato", "medium", from, {
        evento: "recontato_agendado",
        periodo: detection.periodo,
        horario: detection.horario,
        motivacao: detection.motivacao,
        scheduledDate: scheduledDate.toISOString(),
        mensagemOriginal: (detection.originalText || "").slice(0, 200)
      });
    }

    console.log("đ Recontato agendado com sucesso:", {
      user: from,
      nome,
      scheduledDate: scheduledDate.toISOString(),
      periodo: detection.periodo,
      horario: detection.horario,
      motivacao: detection.motivacao
    });

    return { success: true, scheduledDate, agendamento };

  } catch (error) {
    console.error("â Erro ao agendar recontato:", {
      user: from,
      error: error.message
    });

    return { success: false, error: error.message };
  }
}

/* =========================
   EXECUTAR RECONTATO AGENDADO
   Chamada pelo cron job (Passo 5).
========================= */

async function executeScheduledCallback(agendamento) {
  const from = agendamento.user;

  try {
    await connectMongo();

    const lead = await loadLeadProfile(from);

    // Se lead encerrado, cancelar
    if (shouldStopBotByLifecycle(lead)) {
      await db.collection("scheduled_callbacks").updateOne(
        { _id: agendamento._id },
        { $set: { status: "cancelado", cancelledAt: new Date(), motivoCancelamento: "lead_encerrado" } }
      );
      console.log("đ Recontato cancelado: lead em estado terminal.", { user: from });
      return false;
    }

    // Se humano assumiu, cancelar
    if (isHumanAssumedLead(lead || {})) {
      await db.collection("scheduled_callbacks").updateOne(
        { _id: agendamento._id },
        { $set: { status: "cancelado", cancelledAt: new Date(), motivoCancelamento: "humano_assumiu" } }
      );
      console.log("đ Recontato cancelado: humano assumiu.", { user: from });
      return false;
    }

    // Se cadĂȘncia nĂŁo estĂĄ mais pausada (lead jĂĄ respondeu), cancelar
    if (lead?.cadenciaPausadaPorCliente !== true) {
      await db.collection("scheduled_callbacks").updateOne(
        { _id: agendamento._id },
        { $set: { status: "cancelado", cancelledAt: new Date(), motivoCancelamento: "lead_ja_respondeu" } }
      );
      console.log("đ Recontato cancelado: lead jĂĄ retomou conversa.", { user: from });
      return false;
    }

    // Tudo ok â enviar mensagem de recontato
    const candidatoNome = lead?.nomeWhatsApp || lead?.nome || "";
    const nome = !isInvalidLooseNameCandidate(candidatoNome) ? getFirstName(candidatoNome) : "";
    const mensagem = nome
      ? `${nome}, tudo bem? đ Como combinamos, estou retomando nosso contato. VocĂȘ tem uns minutinhos agora?`
      : `Oi! đ Tudo bem? Como combinamos, estou retomando nosso contato. VocĂȘ tem uns minutinhos agora?`;

    await sendWhatsAppMessage(from, mensagem);

    // Salvar no histĂłrico
    const history = await loadConversation(from);
    history.push({
      role: "assistant",
      content: mensagem,
      createdAt: new Date(),
      origem: "recontato_agendado"
    });
    await saveConversation(from, history);

    // Marcar como executado
    await db.collection("scheduled_callbacks").updateOne(
      { _id: agendamento._id },
      { $set: { status: "executado", executedAt: new Date() } }
    );

    // Reativar cadĂȘncia normal
    await saveLeadProfile(from, {
      cadenciaPausadaPorCliente: false,
      cadenciaReativadaEm: new Date(),
      agendamentoRecontato: null
    });

    // Agendar cadĂȘncia normal caso lead nĂŁo responda ao recontato
    await scheduleLeadFollowups(from);

    // Audit
    if (typeof auditSystemEvent === "function") {
      await auditSystemEvent("agendamento_recontato", "medium", from, {
        evento: "recontato_executado",
        scheduledDate: agendamento.scheduledDate?.toISOString?.() || "",
        executedAt: new Date().toISOString()
      });
    }

    console.log("â Recontato agendado executado com sucesso:", {
      user: from,
      nome,
      scheduledDate: agendamento.scheduledDate
    });

    return true;

  } catch (error) {
    console.error("â Erro ao executar recontato agendado:", {
      user: from,
      error: error.message
    });

    const tentativas = (agendamento.tentativas || 0) + 1;
    if (tentativas >= (agendamento.maxTentativas || 3)) {
      await db.collection("scheduled_callbacks").updateOne(
        { _id: agendamento._id },
        { $set: { status: "falhado", tentativas, ultimoErro: error.message } }
      );

      // Reativar cadĂȘncia mesmo com falha
      await saveLeadProfile(from, {
        cadenciaPausadaPorCliente: false,
        cadenciaReativadaEm: new Date(),
        agendamentoRecontato: null
      });
      await scheduleLeadFollowups(from);
    } else {
      // Reagendar para daqui 1 hora
      const novaData = new Date(Date.now() + 60 * 60 * 1000);
      await db.collection("scheduled_callbacks").updateOne(
        { _id: agendamento._id },
        { $set: { scheduledDate: novaData, tentativas, ultimoErro: error.message } }
      );
    }

    return false;
  }
}

function isBusinessTime() {
  const now = getBrazilNow();
  const day = now.getDay(); // 0 = domingo, 6 = sĂĄbado
  const hour = now.getHours();

  const isWeekend = day === 0 || day === 6;

  if (isWeekend) {
    return false;
  }

  return hour >= BUSINESS_START_HOUR && hour < BUSINESS_END_HOUR;
}

function getDelayUntilNextBusinessTime() {
  const now = getBrazilNow();
  const next = new Date(now);

  next.setHours(BUSINESS_START_HOUR, 0, 0, 0);

  if (
    now.getHours() >= BUSINESS_END_HOUR ||
    now.getDay() === 6 ||
    now.getDay() === 0
  ) {
    next.setDate(next.getDate() + 1);
  }

  while (next.getDay() === 0 || next.getDay() === 6) {
    next.setDate(next.getDate() + 1);
  }

  if (
    now.getHours() < BUSINESS_START_HOUR &&
    now.getDay() !== 0 &&
    now.getDay() !== 6
  ) {
    next.setDate(now.getDate());
  }

  return Math.max(next.getTime() - now.getTime(), 0);
}

