  function shouldStopBotByLifecycle(lead = {}) {
  lead = lead || {};

  const status = lead.status || "";
  const fase = lead.faseQualificacao || "";
  const statusOperacional = lead.statusOperacional || "";
  const faseFunil = lead.faseFunil || "";

  const blockedOldValues = [
    "em_atendimento",
    "enviado_crm",
    "fechado",
    "perdido"
  ];

  const blockedOperationalValues = [
    "em_atendimento",
    "enviado_crm",
    "fechado",
    "perdido"
  ];

  const blockedFunnelValues = [
    "crm",
    "encerrado"
  ];

  return (
    blockedOldValues.includes(status) ||
    blockedOldValues.includes(fase) ||
    blockedOperationalValues.includes(statusOperacional) ||
    blockedFunnelValues.includes(faseFunil)
  );
}
   
function isLeadInProtectedFollowupState(lead = {}) {
  const status = lead?.status || "";
  const faseQualificacao = lead?.faseQualificacao || "";
  const statusOperacional = lead?.statusOperacional || "";
  const faseFunil = lead?.faseFunil || "";

  const isHumanOrFinal =
    lead?.botBloqueadoPorHumano === true ||
    lead?.humanoAssumiu === true ||
    lead?.atendimentoHumanoAtivo === true ||
    lead?.crmEnviado === true ||
    lead?.dadosConfirmadosPeloLead === true ||
    ["em_atendimento", "enviado_crm", "fechado", "perdido", "erro_envio_crm"].includes(statusOperacional) ||
    ["enviado_crm", "em_atendimento", "fechado", "perdido", "dados_confirmados"].includes(status) ||
    ["enviado_crm", "em_atendimento", "fechado", "perdido", "dados_confirmados"].includes(faseQualificacao) ||
    ["pre_analise", "crm", "encerrado"].includes(faseFunil);

  const isDataFlow =
    lead?.aguardandoConfirmacaoCampo === true ||
    lead?.aguardandoConfirmacao === true ||
    ["coleta_dados", "confirmacao_dados"].includes(faseFunil) ||
    [
      "coletando_dados",
      "dados_parciais",
      "aguardando_dados",
      "aguardando_confirmacao_campo",
      "aguardando_confirmacao_dados",
      "corrigir_dado",
      "corrigir_dado_final",
      "aguardando_valor_correcao_final"
    ].includes(status) ||
    [
      "coletando_dados",
      "dados_parciais",
      "aguardando_dados",
      "aguardando_confirmacao_campo",
      "aguardando_confirmacao_dados",
      "corrigir_dado",
      "corrigir_dado_final",
      "aguardando_valor_correcao_final"
    ].includes(faseQualificacao);

  const isCadenciaPausada = lead?.cadenciaPausadaPorCliente === true;

  return isHumanOrFinal || isDataFlow || isCadenciaPausada;
}

function historyOrLeadIndicatesTaxExplained(lead = {}, history = []) {
  const etapas = lead?.etapas || {};
  const faseFunil = lead?.faseFunil || "";
  const faseQualificacao = lead?.faseQualificacao || "";

  if (
    etapas.investimento === true ||
    etapas.compromisso === true ||
    lead?.taxaAlinhada === true ||
    faseFunil === "investimento" ||
    faseFunil === "compromisso" ||
    faseQualificacao === "compromisso"
  ) {
    return true;
  }

  const sdrText = Array.isArray(history)
    ? history
        .slice(-25)
        .filter(m => m?.role === "assistant")
        .map(m => m?.content || "")
        .join("\n")
    : "";

  return /(\btaxa de ades[aĂŁ]o\b|\bvalor da ades[aĂŁ]o\b|\bvalor do investimento\b|\bvalor da taxa\b|r\$\s*1[\.,]?990|\b1[\.,]?990\s*reais?\b|\b10\s*x\s*de\s*r?\$?\s*199\b|\b10\s*vezes\s*de\s*r?\$?\s*199\b)/i.test(sdrText);
}

function historyOrLeadIndicatesResponsibilitiesExplained(lead = {}, history = []) {
  const etapas = lead?.etapas || {};
  const faseFunil = lead?.faseFunil || "";

  if (
    etapas.responsabilidades === true ||
    etapas.compromisso === true ||
    faseFunil === "responsabilidades" ||
    faseFunil === "investimento" ||
    faseFunil === "compromisso"
  ) {
    return true;
  }

  const sdrText = Array.isArray(history)
    ? history
        .slice(-25)
        .filter(m => m?.role === "assistant")
        .map(m => m?.content || "")
        .join("\n")
    : "";

  return /(\bresponsabilidades do parceiro\b|\bguarda e conserva[cĂ§][aĂŁ]o\b|\bvendas ativamente\b|\brelacionamento ativo\b|\bcomunica[cĂ§][aĂŁ]o correta\b|\bdepende da sua atua[cĂ§][aĂŁ]o\b)/i.test(sdrText);
}

/*
  Gera mensagem de cadĂȘncia usando os GPTs (PrĂ©-SDR + SDR).
  Em vez de texto hardcoded, os GPTs analisam o histĂłrico completo
  e geram uma mensagem contextual de reengajamento.
*/
async function generateFollowupViaGPTs(from, lead = {}, step = 1, opts = {}) {
  try {
    const history = await loadConversation(from);
    const auditTraceId = generateTraceId();

    const nome = getFirstName(lead.nomeWhatsApp || lead.nome || "");
    const faseFunil = lead.faseFunil || "esclarecimento";
    const etapas = lead.etapas || {};

    // Montar contexto de cadĂȘncia para o PrĂ©-SDR
    const contextoCadencia = [
      opts?.avisoIntent ? opts.avisoIntent : null,
      `CONTEXTO DE CADĂNCIA AUTOMĂTICA (Step ${step} de 5):`,
      `Esta NĂO Ă© uma resposta a uma mensagem do lead.`,
      `Ă uma mensagem de retomada/reengajamento porque o lead parou de responder.`,
      `O lead estĂĄ inativo. A SDR deve enviar UMA mensagem curta e consultiva para reengajar.`,
      step === 1
        ? `IMPORTANTE â INCLUIR NO FINAL DA MENSAGEM:
     Adicione no FINAL da mensagem (sem alterar o conteĂșdo principal) este aviso de opt-out, exatamente como aparece abaixo, em uma nova linha apĂłs o conteĂșdo principal:

     ---
     đŹ Se preferir nĂŁo receber mais MENSAGENS AUTOMĂTICAS de acompanhamento, Ă© sĂł responder *PARAR* (nĂŁo afeta seu cadastro nem qualquer outro contato com a IQG, sĂł estas mensagens automĂĄticas).

     IMPORTANTE: este aviso sĂł aparece nesta primeira mensagem de cadĂȘncia. NĂŁo repita em futuros toques.`
        : null,
      "",
      "REGRAS DA CADĂNCIA:",
      "- Mensagem CURTA: MĂXIMO 280 caracteres E mĂĄximo 2-3 frases",
      "- Tom leve e consultivo, sem pressĂŁo",
      "- NĂO repetir o que jĂĄ foi dito no histĂłrico â VARIE o formato em relaĂ§ĂŁo Ă s Ășltimas mensagens da SDR:",
      "  * Se a Ășltima cadĂȘncia comeĂ§ou com 'Oi!', NĂO comece com 'Oi!' â varie a abertura",
      "  * Se a Ășltima foi pergunta, faĂ§a observaĂ§ĂŁo. Se foi observaĂ§ĂŁo, faĂ§a pergunta",
      "  * Cada step deve ter formato e tom diferentes dos anteriores",
      "  * Se jĂĄ citou R$ 5.000, R$ 1.990, comodato, vitalĂ­cia, 10% comissĂŁo, margem 40%, suporte+treinamento, taxa de adesĂŁo ou prĂ©-anĂĄlise no histĂłrico â NĂO repita; busque outro argumento ou conduza para prĂłximo passo natural",
      "- NĂO falar de temas que ainda nĂŁo foram abordados",
      "- NĂO pedir dados pessoais (nome, CPF, telefone)",
      "- Retomar a conversa de onde parou, baseado no histĂłrico",
      "- Se o lead jĂĄ viu benefĂ­cios, fazer clarity-check especĂ­fico (ex: 'ficou claro como funcionam os benefĂ­cios e o suporte?')",
      "- Se o lead jĂĄ viu estoque, fazer clarity-check especĂ­fico (ex: 'fez sentido como funciona o comodato?')",
      "- Se o lead jĂĄ viu responsabilidades, fazer clarity-check especĂ­fico (ex: 'ficou claro como funciona sua atuaĂ§ĂŁo no dia a dia?')",
      "- Se a taxa jĂĄ foi explicada, perguntar se faz sentido o investimento",
      "- Se o lead estĂĄ em Fase 1 (apresentaĂ§ĂŁo inicial), NĂO mencione",
      "  comodato, vitalĂ­cia, R$ 5.000, renda passiva, margem 40%, ou taxa.",
      "  Apenas reengaje com pergunta leve sobre interesse no programa.",
      "- NĂO mencionar taxa se ela nunca foi explicada no histĂłrico",
      "- NĂO usar **negrito** nem listas numeradas",
      "- Usar *negrito* (1 asterisco) se precisar destacar algo",
      "",
      `Step ${step}/5: ${step <= 2 ? "retomada leve" : step <= 4 ? "retomada consultiva" : "Ășltima tentativa â mencionar Afiliado como alternativa"}`,
      step === 5 ? "ĂLTIMO FOLLOW-UP: mencionar brevemente o Programa de Afiliados como alternativa e incluir o link https://minhaiqg.com.br/ no final" : ""
    ].filter(Boolean).join("\n");

    // Rodar o PrĂ©-SDR com contexto de cadĂȘncia
    const lastSdrText = [...history].reverse().find(m => m.role === "assistant")?.content || "";

    const preSdrResult = await runConsultantAssistant({
      lead: lead,
      history,
      lastUserText: "[CADĂNCIA AUTOMĂTICA â lead inativo]",
      lastSdrText,
      backendStrategicGuidance: [{
        tipo: "cadencia_automatica",
        prioridade: "alta",
        motivo: `Follow-up automĂĄtico step ${step}/5. Lead estĂĄ inativo.`,
        orientacaoParaPreSdr: contextoCadencia
      }],
      auditTraceId
    });

    // Gerar a mensagem da SDR chamando a OpenAI diretamente.
    // Usa o SYSTEM_PROMPT principal da SDR + a orientaĂ§ĂŁo do PrĂ©-SDR.
    const orientacaoPreSdr = [
      "CONTEXTO: esta Ă© uma mensagem de CADĂNCIA AUTOMĂTICA de reengajamento â [lead inativo].",
      "O lead parou de responder. Gere UMA mensagem curta de retomada.",
      "",
      contextoCadencia,
      "",
      "OVERRIDES IMPORTANTES (cadĂȘncia tem prioridade absoluta sobre instruĂ§Ă”es de fase):",
      "- A EXCEĂĂO Ă REGRA DE BREVIDADE da Fase 6 NĂO se aplica aqui â cadĂȘncia sempre 2-3 frases.",
      "- A mensagem-base obrigatĂłria da Fase 6 NĂO se aplica aqui â use apenas retomada curta.",
      "",
      // ââââââââ BLOCO NOVO 1 â PROIBIĂĂES ANTI-BORDĂO (F5.5-4a) ââââââââ
      "đ« PROIBIĂĂES ABSOLUTAS (F5.5-4a â auditoria 26/05 detectou bordĂŁo em 70% das cadĂȘncias):",
      "- PROIBIDO usar a frase 'Quer que eu te explique de forma simples como funciona' (e variantes: 'te explico de forma simples', 'explicar de forma simples', 'de forma simples como funciona').",
      "- PROIBIDO abrir com 'vi que vocĂȘ demonstrou interesse' ou 'percebi seu interesse' ou variantes que reapresentem o que o lead jĂĄ sabe.",
      "- PROIBIDO encerrar com 'fico Ă  disposiĂ§ĂŁo' ou 'estou aqui para ajudar' como Ășnica chamada Ă  aĂ§ĂŁo.",
      "- PROIBIDO usar PERGUNTA RETĂRICA ('fez sentido?', 'ficou alguma dĂșvida?') como ĂNICA pergunta â se usar, acompanhar de pergunta calibrada sobre algo especĂ­fico.",
      "",
      // ââââââââ BLOCO NOVO 2 â INSPECIONE O HISTĂRICO ââââââââ
      "đ INSPECIONE O HISTĂRICO ANTES DE ESCREVER:",
      "- Leia as ĂLTIMAS 3 mensagens da SDR no histĂłrico desta conversa.",
      "- Identifique abertura, estrutura e fechamento usados.",
      "- A nova mensagem DEVE ter abertura DIFERENTE, estrutura DIFERENTE e fechamento DIFERENTE.",
      "- Se a Ășltima cadĂȘncia usou pergunta retĂłrica â use pergunta calibrada agora.",
      "- Se a Ășltima usou 'Oi! đ' â varie a abertura.",
      "- Se jĂĄ mencionou taxa/comodato/R$5.000/R$1.990 â busque Ăąngulo diferente (suporte, treinamento, comissĂŁo vitalĂ­cia, prova social genĂ©rica).",
      "",
      // ââââââââ BLOCO NOVO 3 â VARIE A ABORDAGEM (4 modos) ââââââââ
      "đŻ VARIE A ABORDAGEM ENTRE STEPS (escolha 1 dos 4 modos, alternando):",
      "  âą MODO 1 (pergunta calibrada Voss): 'Como X se encaixa no que vocĂȘ tinha em mente?' / 'O que mais pesa pra vocĂȘ?'",
      "  âą MODO 2 (rotulaĂ§ĂŁo tĂĄtica Voss): 'Parece que [hipĂłtese sobre o silĂȘncio]...' / 'Pelo que conversamos, [observaĂ§ĂŁo]...'",
      "  âą MODO 3 (micro-compromisso Cialdini): 'Posso te enviar [algo especĂ­fico]?' / 'Topa fazer 1 pergunta breve?'",
      "  âą MODO 4 (observaĂ§ĂŁo contextual): 'Lembrei de algo que pode te interessar...' / 'Surgiu informaĂ§ĂŁo nova que talvez ajude...'",
      "",
      // ââââââââ BLOCO F6.2-C3 â CONTEXTO F6 SILENTE (pĂłs-taxa) ââââââââ
      ...(isF6Silente(history) ? [
        "đŻ CONTEXTO F6 SILENTE (F6.2-C3):",
        "Lead jĂĄ recebeu apresentaĂ§ĂŁo da taxa de R$1.990 e silenciou ou respondeu minimalmente. NĂO repita pitch genĂ©rico ('ficou alguma dĂșvida sobre o comodato?'). Use ESTRATĂGIA ESCALONADA conforme o step:",
        "Step 1 â Pergunta calibrada (Voss): 'dos pontos que conversamos, o que mais pesou pra vocĂȘ refletir?'",
        "Step 2 â Reframing ROI: lote R$5.000 em PV cobre taxa R$1.990 nas primeiras vendas",
        "Step 3 â Prova social: parceiros recuperam investimento no primeiro mĂȘs",
        "Step 4 â Ancoragem parcelamento: 10x R$199 sem comprometer fluxo",
        "Mensagem CURTA (2-3 frases), tom consultivo, sem pressĂŁo. NĂO repita estrutura entre cadĂȘncias.",
        "",
      ] : []),
      "ORIENTAĂĂO DO CONSULTOR PRĂ-SDR:",
      `EstratĂ©gia: ${preSdrResult?.estrategiaRecomendada || "manter_nutricao"}`,
      `PrĂłxima aĂ§ĂŁo: ${preSdrResult?.proximaMelhorAcao || "-"}`,
      `Abordagem: ${preSdrResult?.abordagemSugerida || "-"}`,
      `Argumento principal: ${preSdrResult?.argumentoPrincipal || "-"}`,
      `Cuidado principal: ${preSdrResult?.cuidadoPrincipal || "-"}`,
      "",
      "Responda SOMENTE com a mensagem final que serĂĄ enviada ao lead no WhatsApp.",
      "Sem aspas, sem prefixo, sem explicaĂ§ĂŁo. Apenas a mensagem."
    ].join("\n");

    const historyParaSdr = (Array.isArray(history) ? history : [])
      .slice(-12)
      .map(m => ({
        role: m.role === "assistant" ? "assistant" : "user",
        content: String(m.content || "")
      }));

    let mensagem = "";

    try {
      const sdrResponse = await fetch("https://api.openai.com/v1/chat/completions", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          model: process.env.OPENAI_MODEL || "gpt-4o-mini",
          temperature: 0.5,
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            { role: "system", content: orientacaoPreSdr },
            ...historyParaSdr,
            {
              role: "user",
              content: "[GERAR MENSAGEM DE CADĂNCIA â o lead estĂĄ inativo, retome a conversa conforme as orientaĂ§Ă”es acima]"
            }
          ]
        })
      });

      const sdrData = await sdrResponse.json();
      mensagem = sdrData?.choices?.[0]?.message?.content || "";
    } catch (sdrError) {
      console.error("Erro ao chamar SDR para cadĂȘncia:", sdrError.message);
      return null;
    }
    if (!mensagem || !String(mensagem).trim()) {
      console.log("â ïž GPTs nĂŁo geraram mensagem de cadĂȘncia. Usando fallback.", { user: from, step });
      return null; // vai cair no fallback hardcoded
    }

    // Sanitizar para WhatsApp
    const mensagemLimpa = sanitizeWhatsAppText(mensagem);

    console.log("đ€ CadĂȘncia gerada via GPTs:", {
      user: from,
      step,
      mensagem: mensagemLimpa.slice(0, 100)
    });

    // ANTI-REPETIĂĂO NA CADĂNCIA (fix bug-2):
    // Aplica o guard de anti-repetiĂ§ĂŁo estrutural. Se a mensagem gerada
    // repete tema/tokens em relaĂ§ĂŁo ao histĂłrico recente, faz UMA segunda
    // tentativa ao OpenAI com instruĂ§Ă”es reforĂ§adas. Se a 2ÂȘ tambĂ©m
    // repetir, retorna null para o caller cair no fallback hardcoded.
    try {
      const guardResult = applyAntiRepetitionGuard({
        leadText: "",
        respostaFinal: mensagemLimpa,
        currentLead: lead,
        history: historyParaSdr
      });

      if (guardResult?.changed === true) {
        const tokensRepetidos = guardResult.reason?.repeatedTokens || [];
        const temaRepetido = guardResult.reason?.repeatedSameTheme || null;

        await auditSystemEvent("cadencia_repeticao_detectada", "medium", from, {
          step,
          temaRepetido,
          tokensRepetidos,
          mensagemOriginal: mensagemLimpa.slice(0, 200)
        });

        // Monta instruĂ§ĂŁo reforĂ§ada para a regeneraĂ§ĂŁo
        const orientacaoReforcada = [
          orientacaoPreSdr,
          "",
          "â ïž ATENĂĂO â REGENERAĂĂO POR REPETIĂĂO DETECTADA:",
          "A primeira tentativa repetiu tema/tokens da Ășltima resposta da SDR no histĂłrico.",
          temaRepetido ? `Tema repetido: "${temaRepetido}".` : "",
          tokensRepetidos.length > 0 ? `Tokens repetidos: ${tokensRepetidos.join(", ")}.` : "",
          // F8.6 â Camada A: citaĂ§ĂŁo verbatim + regras prescritivas mensurĂĄveis
          "",
          ...(lastSdrText && lastSdrText.length > 0 ? [
            "đ« NĂO REPITA â A ĂLTIMA MENSAGEM DA SDR FOI (verbatim):",
            `"""${lastSdrText.slice(0, 400)}"""`,
            ""
          ] : []),
          "A NOVA mensagem PRECISA ter:",
          "- Primeiras 2-3 PALAVRAS diferentes (compare verbatim)",
          "- Verbos principais diferentes",
          "- TĂłpico CENTRAL diferente (se anterior abordou suporte â use comissĂŁo vitalĂ­cia; se abordou comodato â use ROI; etc.)",
          "- Se anterior fez PERGUNTA â faĂ§a OBSERVAĂĂO. Se fez observaĂ§ĂŁo â faĂ§a pergunta.",
          "REESCREVA com:",
          "- Estrutura DIFERENTE da Ășltima mensagem da SDR (se foi pergunta, faĂ§a observaĂ§ĂŁo; se comeĂ§ou com 'Oi!', NĂO comece com 'Oi!')",
          "- Ăngulo NOVO do tema, sem repetir os mesmos valores monetĂĄrios, frases-chave ou explicaĂ§Ă”es",
          "- Se jĂĄ citou R$ 5.000, R$ 1.990, comodato, 10% comissĂŁo, vitalĂ­cia, margem 40%, suporte+treinamento, taxa de adesĂŁo ou prĂ©-anĂĄlise â NĂO repita; busque outro argumento ou conduza para prĂłximo passo natural",
          "- Mantenha as REGRAS DA CADĂNCIA originais (curta, 2-3 frases, tom consultivo)"
        ].filter(Boolean).join("\n");

        // F8.6 â instrumentaĂ§ĂŁo Camada B (vars antes do retry fetch)
        const retryStartTs = Date.now();
        let retryHttpStatus = null;
        let retryResponseLen = 0;
        let retryResponseExcerpt = null;

        // Retry interno: 1 segunda tentativa
        const retryResponse = await fetch("https://api.openai.com/v1/chat/completions", {
          method: "POST",
          headers: {
            Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            model: process.env.OPENAI_MODEL || "gpt-4o-mini",
            temperature: 0.7,
            messages: [
              { role: "system", content: SYSTEM_PROMPT },
              { role: "system", content: orientacaoReforcada },
              ...historyParaSdr,
              { role: "user", content: "[GERAR MENSAGEM DE CADĂNCIA â regeneraĂ§ĂŁo apĂłs detecĂ§ĂŁo de repetiĂ§ĂŁo, varie o formato e o Ăąngulo]" }
            ]
          })
        });
        retryHttpStatus = retryResponse.status;  // F8.6

        if (retryResponse.ok) {
          const retryData = await retryResponse.json();
          const retryMensagem = retryData?.choices?.[0]?.message?.content || "";
          retryResponseLen = retryMensagem.length;  // F8.6
          retryResponseExcerpt = retryMensagem.slice(0, 150) || null;  // F8.6
          const retryLimpa = sanitizeWhatsAppText(retryMensagem);

          if (retryLimpa) {
            // Valida se o retry resolveu a repetiĂ§ĂŁo
            const retryGuard = applyAntiRepetitionGuard({
              leadText: "",
              respostaFinal: retryLimpa,
              currentLead: lead,
              history: historyParaSdr
            });

            if (retryGuard?.changed !== true) {
              // Retry OK â sem repetiĂ§ĂŁo. Loga sucesso e retorna a nova mensagem.
              await auditSystemEvent("cadencia_regenerada_apos_repeticao", "low", from, {
                step,
                mensagemAnterior: mensagemLimpa.slice(0, 200),
                mensagemNova: retryLimpa.slice(0, 200)
              });
              return retryLimpa;
            }

            // Retry tambĂ©m repetiu â descarta e cai no fallback
            await auditSystemEvent("cadencia_retry_falhou", "medium", from, {
              step,
              motivoFalha: "retry_tambem_repetiu",
              // F8.6 â instrumentaĂ§ĂŁo Camada B
              latency_ms: Date.now() - retryStartTs,
              http_status: retryHttpStatus,
              attempt_n: 2,
              response_len: retryResponseLen,
              response_excerpt: retryResponseExcerpt
            });
            return null;
          }
        }

        // Retry falhou (resposta vazia ou HTTP erro) â descarta e cai no fallback
        await auditSystemEvent("cadencia_retry_falhou", "medium", from, {
          step,
          motivoFalha: "retry_resposta_vazia_ou_erro_http",
          // F8.6 â instrumentaĂ§ĂŁo Camada B
          latency_ms: Date.now() - retryStartTs,
          http_status: retryHttpStatus,
          attempt_n: 2,
          response_len: retryResponseLen,
          response_excerpt: retryResponseExcerpt
        });
        return null;
      }
    } catch (guardError) {
      // Erro no guard: NĂO bloqueia a mensagem original â segue com ela.
      // Anti-repetiĂ§ĂŁo Ă© melhoria, nĂŁo prĂ©-requisito de envio.
      console.error("Erro no guard anti-repetiĂ§ĂŁo da cadĂȘncia (ignorado):", guardError?.message || guardError);
    }

    return mensagemLimpa;
  } catch (error) {
    console.error("Erro ao gerar cadĂȘncia via GPTs:", { user: from, step, error: error.message });
    await auditSystemEvent("erro_sistema", "high", from, {
      origem: "generateFollowupViaGPTs",
      step: step,
      erro: error.message
    });
    return null; // fallback para texto hardcoded
  }
}

async function flagHotLeadForHumanHandoff(from) {
  await saveLeadProfile(from, {
    necessitaAtencaoHumanaDashboard: true,
    motivoAtencaoHumanaDashboard: "CadĂȘncia encerrada (step 5) com lead em fase avanĂ§ada â requer atendimento humano.",
    prioridadeAtencaoHumanaDashboard: "alta",
    atencaoHumanaDashboardEm: new Date()
  });

  console.log("đ Lead quente em encerramento de cadĂȘncia â marcado para Janela 2:", { user: from });

  if (typeof auditSystemEvent === "function") {
    await auditSystemEvent("decisao_backend", "medium", from, {
      evento: "lead_quente_movido_janela_2_step_5",
      motivo: "CadĂȘncia encerrada com lead em fase avanĂ§ada"
    });
  }
}

/*
  Bug 5 â handoff humano quando regeneraĂ§ĂŁo nĂŁo elimina crĂ­ticos.

  Distinto de flagHotLeadForHumanHandoff (que cobre encerramento de cadĂȘncia
  com lead em fase avanĂ§ada): aqui o gatilho Ă© "regeneraĂ§ĂŁo de resposta da
  SDR falhou em eliminar violaĂ§Ă”es crĂ­ticas apĂłs N tentativas". O lead recebe
  uma mensagem segura e cai na Janela 2 com motivo distinto para o dashboard
  diferenciar os dois casos.
*/
async function flagLeadForRegenerationFailureHandoff(from, criticosRemanescentes = []) {
  const tipos = criticosRemanescentes.map(f => f.tipo).join(", ") || "desconhecido";

  await saveLeadProfile(from, {
    necessitaAtencaoHumanaDashboard: true,
    motivoAtencaoHumanaDashboard: `RegeneraĂ§ĂŁo de resposta da SDR nĂŁo eliminou violaĂ§Ă”es crĂ­ticas apĂłs 2 tentativas (${tipos}). Conversa precisa de atenĂ§ĂŁo humana antes de seguir.`,
    prioridadeAtencaoHumanaDashboard: "alta",
    atencaoHumanaDashboardEm: new Date()
  });

  console.error("đš Lead marcado para Janela 2: regeneraĂ§ĂŁo falhou em eliminar crĂ­ticos.", {
    user: from,
    criticosRemanescentes: tipos
  });

  if (typeof auditSystemEvent === "function") {
    await auditSystemEvent("regeneracao_sdr_fallback_humano", "high", from, {
      tentativas: 2,
      criticosRemanescentes: criticosRemanescentes.map(f => f.tipo),
      criticosQueExigiramHandoff: criticosRemanescentes.filter(cr => (cr?.tipo || cr) !== "disciplina_funil").map(cr => cr?.tipo || cr),
      todosCriticosNoMomentoHandoff: criticosRemanescentes.map(cr => cr?.tipo || cr)
    });
  }
}

/*
  Bug 8 â handoff para Janela 2 quando lead declara ser revendedor/lojista.

  AnĂĄlogo a flagHotLeadForHumanHandoff (encerramento de cadĂȘncia com lead
  quente) e flagLeadForRegenerationFailureHandoff (regeneraĂ§ĂŁo falhou).
  DistinĂ§ĂŁo no dashboard via motivo especĂ­fico para o operador identificar
  o caso e oferecer o caminho comercial correto (nĂŁo Parceiro Homologado).
*/
async function flagLeadAsRevendedorLojista(from, contexto = {}) {
  await saveLeadProfile(from, {
    necessitaAtencaoHumanaDashboard: true,
    motivoAtencaoHumanaDashboard: "Lead declarou ser lojista/revendedor/representante comercial â caminho comercial diferente do Programa Parceiro Homologado, exige atendimento humano da equipe IQG.",
    prioridadeAtencaoHumanaDashboard: "alta",
    atencaoHumanaDashboardEm: new Date(),
    leadEhRevendedorLojista: true,
    leadEhRevendedorLojistaEm: new Date()
  });

  console.log("đȘ Lead marcado como revendedor/lojista â Janela 2:", {
    user: from,
    origem: contexto?.origem || null,
    motivoHeuristica: contexto?.motivoHeuristica || null,
    trechoMatch: contexto?.trechoMatch || null
  });

  if (typeof auditSystemEvent === "function") {
    await auditSystemEvent("lead_declarou_revendedor_lojista", "medium", from, {
      origem: contexto?.origem || null,
      motivoHeuristica: contexto?.motivoHeuristica || null,
      trechoMatch: contexto?.trechoMatch || null
    });
  }
}

