const leadFezPerguntaEspecifica =
  String(text || "").includes("?") ||
  /\b(estoque|comodato|taxa|valor|investimento|contrato|responsabilidade|comissao|comissĂŁo|kit|produto|afiliado|link)\b/i.test(text);

if (
  respostaPareceReinicioDoFunil &&
  !leadFezPerguntaEspecifica &&
  getCurrentFunnelStage(currentLead) > 1
) {
  sdrReviewFindings.push({
    tipo: "tentativa_reiniciar_funil",
    prioridade: "alta",
    orientacao:
      "A SDR tentou reiniciar o funil com explicaĂ§ĂŁo genĂ©rica, mesmo o lead jĂĄ estando mais avanĂ§ado. Reescrever sem voltar ao inĂ­cio, mantendo a fase atual e conduzindo para o prĂłximo passo natural."
  });

  console.log("đ§­ RevisĂŁo solicitada: SDR tentou reiniciar o funil:", {
    user: from,
    ultimaMensagemLead: text
  });
}

     // đ„ Ajuste fino de gĂȘnero (fallback)
const genero = currentLead?.generoProvavel || extractedData?.generoProvavel;

if (genero === "masculino") {
  respostaFinal = respostaFinal
    .replace(/\binteressada\b/gi, "interessado")
    .replace(/\bpronta\b/gi, "pronto")
    .replace(/\bpreparada\b/gi, "preparado");
}

if (genero === "feminino") {
  respostaFinal = respostaFinal
    .replace(/\binteressado\b/gi, "interessada")
    .replace(/\bpronto\b/gi, "pronta")
    .replace(/\bpreparado\b/gi, "preparada");
}
     
const nomeCurto = getFirstName(currentLead?.nomeWhatsApp || currentLead?.nome || "");

if (
  nomeCurto &&
  shouldUseName(state) &&
  !respostaFinal.toLowerCase().includes(nomeCurto.toLowerCase())
) {
  const novaResposta = respostaFinal.replace(
    /(Perfeito đ|Ătimo đ|Certo đ|Legal đ|Show đ)/,
    `$1 ${nomeCurto},`
  );

  if (novaResposta !== respostaFinal) {
    respostaFinal = novaResposta;
    state.lastNameUse = Date.now();
  }
}
     
// F7.5 â Substituidor programĂĄtico de bordĂŁo "fico Ă  disposiĂ§ĂŁo".
// Enforcement HARD (determinĂ­stico, antes do envio). Cobre 6 variantes
// principais (fico/estou/ficamos/sigo/seguimos/estamos). Idempotente:
// msgs jĂĄ limpas passam intactas. Detecta FRASE COMPLETA (atĂ© pontuaĂ§ĂŁo)
// para nĂŁo quebrar gramĂĄtica. VariaĂ§ĂŁo rotativa de substituiĂ§ĂŁo evita
// criar novo bordĂŁo. NĂO substitui o detector @28704 (badPatterns soft);
// Ă© a rede HARD complementar.
// F8.1 â FamĂ­lia ampliada: 3 padrĂ”es SEGUROS (zero falsos positivos).
// "se precisar" e "qualquer dĂșvida" catalogados pra F8.1b
// (precisam guard contextual pra evitar modificaĂ§ĂŁo de templates
// hardcoded @26800, @27230, @28375).
const F75_BORDAO_FECHAMENTO_REGEX =
  /(?:^|[\s,â.;])(?:fico|estou|ficamos|sigo|seguimos|estamos)\s+[Ă a]\s+disposi[Ă§c][ĂŁa]o[^.!?\n]*[.!?]?|(?:^|[\s,â.;])estou aqui p(?:ara|ra) ajudar[^.!?\n]*[.!?]?|(?:^|[\s,â.;])fique [Ă a] vontade[^.!?\n]*[.!?]?/gi;

const F75_SUBSTITUTOS = [
  "Se quiser, Ă© sĂł me chamar por aqui.",
  "Qualquer coisa, me chama por aqui.",
  "Se fizer sentido, Ă© sĂł me chamar.",
  "Ă sĂł me chamar por aqui."
];

// Counter mĂłdulo-level pra variaĂ§ĂŁo ROTATIVA ENTRE chamadas separadas
// (sem isso, cada call reinicia em 0 e sempre usa F75_SUBSTITUTOS[0] â
// cria novo bordĂŁo. Counter global garante â„3 variantes em 4 disparos
// consecutivos. Sem persistĂȘncia: reseta a cada restart do server, OK.)
let F75_SUBSTITUTO_COUNTER = 0;

function enforceNoBordaoFechamento(message) {
  if (!message || typeof message !== "string") return message;
  F75_BORDAO_FECHAMENTO_REGEX.lastIndex = 0;
  if (!F75_BORDAO_FECHAMENTO_REGEX.test(message)) return message;
  F75_BORDAO_FECHAMENTO_REGEX.lastIndex = 0;
  return message.replace(F75_BORDAO_FECHAMENTO_REGEX, (match) => {
    const leadingSep = match.match(/^[\s,â.;]/)?.[0] || "";
    const substituto = F75_SUBSTITUTOS[F75_SUBSTITUTO_COUNTER % F75_SUBSTITUTOS.length];
    F75_SUBSTITUTO_COUNTER++;
    return (leadingSep === "." || leadingSep === "!" || leadingSep === "?")
      ? `${leadingSep} ${substituto}`
      : ` ${substituto}`;
  }).replace(/\s+/g, " ").replace(/\s+([.!?,])/g, "$1").trim();
}

// F8.2 â Helper simĂ©trico ao F7.5 pra "ficou alguma dĂșvida"
// Cobre os 16 GPT-livres que F7.6 hardcoded nĂŁo pega (Patterns A/B/C)
const F77_FICOU_DUVIDA_REGEX =
  /(?:^|[\s,â.;])(?:e\s+|se\s+|que\s+|ou\s+)?ficou alguma d[Ășu]vida[^.!?\n]*[.!?]?/gi;

const F77_FICOU_DUVIDA_SUBSTITUTOS = [
  "Ficou claro o que conversamos atĂ© aqui?",
  "Do que vimos, o que mais fez sentido pra vocĂȘ?",
  "Tem algum ponto especĂ­fico que quer reforĂ§ar?",
  "Qual parte ficou mais clara pra vocĂȘ?"
];

let F77_FICOU_DUVIDA_COUNTER = 0;

function enforceNoFichouAlgumaDuvida(message) {
  if (!message || typeof message !== "string") return message;
  F77_FICOU_DUVIDA_REGEX.lastIndex = 0;
  if (!F77_FICOU_DUVIDA_REGEX.test(message)) return message;
  F77_FICOU_DUVIDA_REGEX.lastIndex = 0;
  return message.replace(F77_FICOU_DUVIDA_REGEX, (match) => {
    const leadingSep = match.match(/^[\s,â.;]/)?.[0] || "";
    const sub = F77_FICOU_DUVIDA_SUBSTITUTOS[F77_FICOU_DUVIDA_COUNTER % F77_FICOU_DUVIDA_SUBSTITUTOS.length];
    F77_FICOU_DUVIDA_COUNTER++;
    return (leadingSep === "." || leadingSep === "!" || leadingSep === "?")
      ? `${leadingSep} ${sub}` : ` ${sub}`;
  }).replace(/\s+/g, " ").replace(/\s+([.!?,])/g, "$1").trim();
}

// F8.Îł.2 â Enforcer programĂĄtico de clarity-check apĂłs explicaĂ§ĂŁo de etapa.
//
// Problema (auditoria 2026-05-28): sĂł 6% das msgs SDR tĂȘm clarity-check
// (vs ~50% esperado). 61% dos leads suspeitos com 0 etapas marcadas estĂŁo
// no padrĂŁo P1: SDR explicou substantivo MAS NĂO perguntou "ficou claro?".
// â F7.4b detector NUNCA dispara porque clarity-check nĂŁo existe na msg.
//
// SoluĂ§ĂŁo simĂ©trica a F7.5/F8.2: append determinĂ­stico de clarity-check
// quando SDR explicou etapa NOVA e nĂŁo fechou com pergunta. NĂŁo toca o
// detector F7.4b nem o prompt â sĂł adiciona o gatilho que faltava.
//
// 7 HARD LIMITS:
//   1. SKIP se msg jĂĄ contĂ©m CLARITY_CHECK_REGEX (idempotente)
//   2. SKIP se msg.length < 80 (resposta curta â  explicaĂ§ĂŁo substantiva)
//   3. SKIP se faseFunil â {"", "esclarecimento"} (nĂŁo tocar fases avanĂ§adas)
//   4. SKIP se etapa-alvo jĂĄ marcada (currentLead.etapas[step] === true)
//   5. SKIP se status terminal (fechado/perdido/em_atendimento/enviado_crm)
//   6. SKIP em fluxo cadĂȘncia (NĂO integrado em @22994; sĂł LIVE @30164)
//   7. SKIP etapas com gates prĂłprios (investimento, compromisso)
//
// Etapa-alvo: primeira em [programa, beneficios, estoque, responsabilidades]
// detectada como explicada AGORA e ainda nĂŁo marcada em currentLead.etapas.
const F8GAMMA2_CLARITY_CHECK_BY_STEP = {
  programa: [
    "Ficou claro como funciona o programa?",
    "Faz sentido atĂ© aqui?",
    "Deu pra entender o programa?"
  ],
  beneficios: [
    "Ficou claro o suporte que vocĂȘ teria?",
    "Faz sentido como a gente te apoia?",
    "Deu pra entender os benefĂ­cios?"
  ],
  estoque: [
    "Ficou claro como funciona o lote inicial?",
    "Faz sentido o esquema do comodato?",
    "Deu pra entender como o estoque Ă© entregue?"
  ],
  responsabilidades: [
    "Ficou claro o que fica sob sua responsabilidade?",
    "Faz sentido a divisĂŁo de responsabilidades?",
    "Deu pra entender a parte do parceiro?"
  ]
};

// Counter mĂłdulo-level por etapa â variaĂ§ĂŁo rotativa entre chamadas
// (mesmo padrĂŁo F75_SUBSTITUTO_COUNTER @28808 e F77_FICOU_DUVIDA_COUNTER @28837).
const F8GAMMA2_COUNTERS = {
  programa: 0,
  beneficios: 0,
  estoque: 0,
  responsabilidades: 0
};

async function enforceClarityCheckAfterExplanation(message, from, currentLead) {
  if (!message || typeof message !== "string") return message;

  // Limit 1: idempotente â se jĂĄ tem clarity-check, NĂO duplica
  if (CLARITY_CHECK_REGEX.test(message)) return message;

  // Limit 2: msg curta nĂŁo Ă© explicaĂ§ĂŁo substantiva
  if (message.length < 80) return message;

  // Limit 3: fora de esclarecimento, nĂŁo interferir
  const fase = currentLead?.faseFunil || "";
  if (fase !== "" && fase !== "esclarecimento") return message;

  // Limit 5: status terminal/avanĂ§ado
  const status = currentLead?.status || "";
  if (["fechado", "perdido", "em_atendimento", "enviado_crm",
       "erro_dados", "erro_envio_crm"].includes(status)) return message;

  // Detecta etapas explicadas NA MENSAGEM ATUAL (reusa detector F7.4b/canonical)
  const explainedNow = iqgDetectFunnelStepsExplainedInText(message);
  const etapasAtuais = currentLead?.etapas || {};

  // Limit 4 + 7: primeira etapa-alvo em ordem funil; exclui investimento+compromisso
  let stepAlvo = null;
  for (const step of ["programa", "beneficios", "estoque", "responsabilidades"]) {
    if (explainedNow[step] && !etapasAtuais[step]) {
      stepAlvo = step;
      break;
    }
  }
  if (!stepAlvo) return message;

  // RotaĂ§ĂŁo determinĂ­stica por etapa
  const variantes = F8GAMMA2_CLARITY_CHECK_BY_STEP[stepAlvo];
  const substituto = variantes[F8GAMMA2_COUNTERS[stepAlvo] % variantes.length];
  F8GAMMA2_COUNTERS[stepAlvo]++;

  const original = message;
  const trimmed = original.replace(/[\s]+$/, "");
  const separador = /[.!?]$/.test(trimmed) ? " " : ". ";
  const result = trimmed + separador + substituto;

  // Audit (fire-and-forget â nĂŁo bloqueia envio)
  auditSystemEvent("clarity_check_appended_F8gamma2", "low", from, {
    stepExplained: stepAlvo,
    clarityCheckUsed: substituto,
    lastSdrLen: original.length,
    reason: "etapa_nova_explicada_sem_clarity_check"
  }).catch(() => {});

  return result;
}

// F8.1b â Substituidor "se precisar" + "qualquer dĂșvida" com guards contextuais.
//
// CatĂĄlogo F8.1: regex simples agressiva pegaria templates hardcoded junto com
// GPT-livre. SoluĂ§ĂŁo: 5 hard limits + idempotĂȘncia hardcoded. REUSA
// F75_SUBSTITUTOS + F75_SUBSTITUTO_COUNTER (famĂ­lia semĂąntica "fechamento informal"
// = F7.5 + F8.1 + F8.1b â telemetria unificada via counter compartilhado).
//
// Templates protegidos (idempotĂȘncia hardcoded + status/fase guards):
//   T1 @26884 â despedida_apos_afiliado (status â "perdido")
//   T2 @28459 â guardrail pĂłs-CRM (status="enviado_crm" OR faseFunil="crm")
//   T4 @27314 â confirmedMsg pĂłs-coleta (faseQ="aguardando_confirmacao_dados")
//
// 5 HARD LIMITS:
//   1. IdempotĂȘncia hardcoded â texto contĂ©m marcador T1/T2/T4 (defesa profunda)
//   2. Status terminal/avanĂ§ado (fechado/perdido/enviado_crm/em_atendimento/erro_*)
//   3. Fase de coleta (faseQualificacao em coletando_dados/etc)
//   4. Rota/fluxo afiliado (rota OR status OR faseQ OR faseFunil = "afiliado")
//   5. CadĂȘncia â SKIP via nĂŁo-integraĂ§ĂŁo em @22994-22995 (escopo LIVE only)
//
// Cobertura projetada: 97% das ocorrĂȘncias GPT-livres (32/33 no JSON 28/05).
// Falsos positivos esperados: ~0. Bucket E (status afiliado isolado) coberto
// pelo Limit 4 refinado.

const F81B_SE_PRECISAR_REGEX =
  /(?:^|[\s,â.;])se precisar[^.!?\n]*[.!?]?/gi;

const F81B_QUALQUER_DUVIDA_REGEX =
  /(?:^|[\s,â.;])(?:e\s+|pra\s+|para\s+|se\s+|que\s+|ou\s+)?qualquer d[Ășu]vida(?! sobre)[^.!?\n]*[.!?]?/gi;

// Defesa em profundidade â idempotĂȘncia por marcador hardcoded dos 3 templates.
// Status/fase guards (Limits 2-4) jĂĄ bloqueariam, mas marker textual Ă© proteĂ§ĂŁo
// independente caso lifecycle nĂŁo tenha sido atualizado ainda.
const F81B_HARDCODED_MARKERS = /foi um prazer conversar com vocĂȘ|seus dados jĂĄ estĂŁo com a equipe comercial da IQG|Encaminhei seus dados para a equipe comercial/i;

async function enforceNoSePrecisarNoQualquerDuvida(message, from, currentLead) {
  if (!message || typeof message !== "string") return message;

  // Limit 1: idempotĂȘncia hardcoded â preserva T1/T2/T4 mesmo se status atrasado
  if (F81B_HARDCODED_MARKERS.test(message)) return message;

  // Limit 2: status terminal/avanĂ§ado
  const status = currentLead?.status || "";
  if (["fechado", "perdido", "enviado_crm", "em_atendimento",
       "erro_dados", "erro_envio_crm"].includes(status)) return message;

  // Limit 3: fase de coleta de dados
  const faseQ = currentLead?.faseQualificacao || "";
  if (["coletando_dados", "aguardando_confirmacao_dados",
       "aguardando_dados", "dados_confirmados"].includes(faseQ)) return message;

  // Limit 4: rota/fluxo afiliado (4 condiĂ§Ă”es â refinado pĂłs-anomalia A.4 Bucket E)
  const rota = currentLead?.rotaComercial || "";
  const faseFunil = currentLead?.faseFunil || "";
  if (rota === "afiliado" || status === "afiliado" ||
      faseQ === "afiliado" || faseFunil === "afiliado") return message;

  // Detecta padrĂ”es (lastIndex reset entre testes â regex /g requer)
  F81B_SE_PRECISAR_REGEX.lastIndex = 0;
  const hasSP = F81B_SE_PRECISAR_REGEX.test(message);
  F81B_SE_PRECISAR_REGEX.lastIndex = 0;
  F81B_QUALQUER_DUVIDA_REGEX.lastIndex = 0;
  const hasQD = F81B_QUALQUER_DUVIDA_REGEX.test(message);
  F81B_QUALQUER_DUVIDA_REGEX.lastIndex = 0;
  if (!hasSP && !hasQD) return message;

  let result = message;
  const patternsHit = [];

  if (hasSP) {
    result = result.replace(F81B_SE_PRECISAR_REGEX, (match) => {
      const leadingSep = match.match(/^[\s,â.;]/)?.[0] || "";
      const sub = F75_SUBSTITUTOS[F75_SUBSTITUTO_COUNTER % F75_SUBSTITUTOS.length];
      F75_SUBSTITUTO_COUNTER++;
      return (leadingSep === "." || leadingSep === "!" || leadingSep === "?")
        ? `${leadingSep} ${sub}` : ` ${sub}`;
    });
    patternsHit.push("se_precisar");
  }

  // Re-test pĂłs-1Âș replace â "qualquer dĂșvida" pode ter sido consumida na frase de "se precisar"
  F81B_QUALQUER_DUVIDA_REGEX.lastIndex = 0;
  if (F81B_QUALQUER_DUVIDA_REGEX.test(result)) {
    F81B_QUALQUER_DUVIDA_REGEX.lastIndex = 0;
    result = result.replace(F81B_QUALQUER_DUVIDA_REGEX, (match) => {
      const leadingSep = match.match(/^[\s,â.;]/)?.[0] || "";
      const sub = F75_SUBSTITUTOS[F75_SUBSTITUTO_COUNTER % F75_SUBSTITUTOS.length];
      F75_SUBSTITUTO_COUNTER++;
      return (leadingSep === "." || leadingSep === "!" || leadingSep === "?")
        ? `${leadingSep} ${sub}` : ` ${sub}`;
    });
    patternsHit.push("qualquer_duvida");
  }

  result = result.replace(/\s+/g, " ").replace(/\s+([.!?,])/g, "$1").trim();

  if (result !== message) {
    auditSystemEvent("se_precisar_qualquer_duvida_replaced_F81b", "low", from, {
      patternsHit,
      lastSdrLen: message.length,
      resultLen: result.length,
      originalExcerpt: message.slice(0, 200),
      reason: "bordao_fechamento_familia_F75"
    }).catch(() => {});
  }

  return result;
}

// đ„ DETECTOR DE RESPOSTA RUIM DA IA
function isBadResponse(text = "") {
  const t = text.toLowerCase().trim();

  if (!t) return true;

  // respostas genĂ©ricas ruins
  const badPatterns = [
    "como posso ajudar",
    "em que posso ajudar",
    "estou aqui para ajudar",
    "fico Ă  disposiĂ§ĂŁo",
    "qualquer dĂșvida me avise",
    "ok đ",
    "certo đ"
  ];

  if (badPatterns.some(p => t.includes(p))) return true;

  // muito curta, sem valor
  if (t.length < 15) return true;

  // sem pergunta e muito curta, sem conduĂ§ĂŁo
  if (!t.includes("?") && t.length < 80) return true;

  return false;
}

