/* =========================
   ROTA DE DIAGNĂSTICO â investigaĂ§ĂŁo Bug 20 (mensagens perdidas)
   Uso: GET /diagnostico-anderson?senha=SENHA
   Read-only. NĂŁo altera nada. Pode ser removida depois.
   ========================= */
app.get("/diagnostico-anderson", async (req, res) => {
  if (!requireDashboardAuth(req, res)) return;

  try {
    await connectMongo();

    const userTarget = "5532920001830";
    const userMaskedRegex = /5532.*30/;

    // 1. Conversa completa do Anderson em conversations
    const conversation = await db.collection("conversations").findOne(
      { user: userTarget },
      { projection: { messages: 1, totalMessages: 1, createdAt: 1, updatedAt: 1 } }
    );

    const messagesFromMongo = (conversation?.messages || []).map(m => ({
      role: m.role,
      content: m.content,
      createdAt: m.createdAt
    }));

    // 2. Buffer ĂłrfĂŁo do Anderson + contagem global
    const bufferOrfao = await db.collection("incoming_message_buffers").find({
      $or: [
        { _id: userTarget },
        { user: userTarget }
      ]
    }).toArray();

    const totalBuffersGlobal = await db.collection("incoming_message_buffers")
      .countDocuments({});

    // 3. Audit events do Anderson â todos
    const auditAll = await db.collection("audit_events").find({
      $or: [
        { userMasked: userMaskedRegex },
        { user: userTarget }
      ]
    })
    .sort({ timestamp: 1 })
    .project({
      timestamp: 1,
      component: 1,
      eventType: 1,
      severity: 1,
      "payload.mensagemLead": 1,
      "payload.respostaFinal": 1,
      "payload.criticosRemanescentes": 1,
      "payload.tiposIgnorados": 1
    })
    .toArray();

    // 4. Buscas especĂ­ficas por frases-chave nos audits
    const buscarFrase = async (regex) => {
      const docs = await db.collection("audit_events").find({
        $and: [
          { $or: [ { userMasked: userMaskedRegex }, { user: userTarget } ] },
          { $or: [
            { "payload.mensagemLead": { $regex: regex, $options: "i" } },
            { "payload.respostaFinal": { $regex: regex, $options: "i" } },
            { "payload.text": { $regex: regex, $options: "i" } }
          ] }
        ]
      }).project({
        timestamp: 1,
        eventType: 1,
        component: 1,
        "payload.mensagemLead": 1,
        "payload.text": 1
      }).toArray();
      return docs;
    };

    const buscaRepresentante = await buscarFrase("representante");
    const buscaDistribuidor = await buscarFrase("distribuidor");
    const buscaValidade = await buscarFrase("validade");
    const buscaExperiencia = await buscarFrase("28 anos");

    // 5. Resumo agregado por eventType
    const resumoEventTypes = {};
    for (const ev of auditAll) {
      resumoEventTypes[ev.eventType] = (resumoEventTypes[ev.eventType] || 0) + 1;
    }

    return res.json({
      _meta: {
        geradoEm: new Date().toISOString(),
        userAlvo: userTarget,
        descricao: "Diagnostico Bug 20 - Anderson"
      },

      conversations: {
        totalMessagesField: conversation?.totalMessages || 0,
        countRealDoArray: messagesFromMongo.length,
        countUserRole: messagesFromMongo.filter(m => m.role === "user").length,
        countAssistantRole: messagesFromMongo.filter(m => m.role === "assistant").length,
        createdAt: conversation?.createdAt || null,
        updatedAt: conversation?.updatedAt || null,
        mensagensCompletas: messagesFromMongo
      },

      buffer: {
        totalGlobalNoSistema: totalBuffersGlobal,
        anderson: bufferOrfao
      },

      auditEvents: {
        totalGeral: auditAll.length,
        resumoPorEventType: resumoEventTypes,
        amostraCronologica: auditAll
      },

      buscaPorFrase: {
        representante: {
          count: buscaRepresentante.length,
          eventos: buscaRepresentante
        },
        distribuidor: {
          count: buscaDistribuidor.length,
          eventos: buscaDistribuidor
        },
        validade: {
          count: buscaValidade.length,
          eventos: buscaValidade
        },
        "28 anos": {
          count: buscaExperiencia.length,
          eventos: buscaExperiencia
        }
      }
    });

  } catch (error) {
    console.error("Erro em /diagnostico-anderson:", error);
    return res.status(500).json({
      ok: false,
      error: error.message,
      stack: error.stack
    });
  }
});

/* =========================
   ROTA DE DIAGNĂSTICO â auditoria forense 22/05/2026
   Uso: GET /diagnostico-22-05-2026?senha=SENHA
   Read-only. 8 queries (A-H). Pode ser removida apĂłs anĂĄlise.
   ========================= */
app.get("/diagnostico-22-05-2026", async (req, res) => {
  if (!requireDashboardAuth(req, res)) return;

  try {
    await connectMongo();

    const result = {
      geradoEm: new Date().toISOString(),
      descricao: "DiagnĂłstico forense 22/05/2026 â Bugs 1/2/3 + Edson Chimini"
    };

    // QUERY A â estado completo do lead Edson + detecĂ§ĂŁo de campos inexistentes
    const camposEsperados = [
      "taxaAlinhada", "wantsAffiliate", "priceObjection", "humanRequest",
      "positiveCommitment", "paymentIntent", "riskObjection",
      "leadPediuHumano", "solicitouAtendimentoHumano",
      "faseQualificacao", "status", "statusOperacional", "rotaComercial",
      "etapas", "dadosConfirmadosPeloLead", "crmEnviado",
      "followupStep", "proximoFollowupEm", "followupVersionDb", "ultimoFollowupEm",
      "nome", "cpf", "telefone", "cidade", "estado",
      "statusDashboard", "statusVisualDashboard", "statusAnteriorDashboard",
      "botBloqueadoPorHumano", "humanoAssumiu", "atendimentoHumanoAtivo",
      "encerradoPor", "origemEncerramento", "motivoPerda",
      "reativadoPeloDashboardEm", "semanticIntent"
    ];
    const projectionA = {};
    camposEsperados.forEach(f => { projectionA[f] = 1; });
    const leadEdson = await db.collection("leads").findOne(
      { user: "5554996223975" },
      { projection: projectionA }
    );
    const camposPresentes = leadEdson ? Object.keys(leadEdson) : [];
    const camposInexistentes = camposEsperados.filter(f => !camposPresentes.includes(f));
    result.queryA_leadEdson = {
      documentExiste: leadEdson !== null,
      document: leadEdson,
      camposInexistentes
    };

    // QUERY B â contagens de flags do classificador (validaĂ§ĂŁo Bug 1)
    result.queryB_contagensFlags = {
      wantsAffiliate: await db.collection("leads").countDocuments({ wantsAffiliate: true }),
      priceObjection: await db.collection("leads").countDocuments({ priceObjection: true }),
      humanRequest: await db.collection("leads").countDocuments({ humanRequest: true }),
      positiveCommitment: await db.collection("leads").countDocuments({ positiveCommitment: true }),
      paymentIntent: await db.collection("leads").countDocuments({ paymentIntent: true }),
      riskObjection: await db.collection("leads").countDocuments({ riskObjection: true })
    };

    // QUERY C â step 5 sem encerramento (validaĂ§ĂŁo Bug 3)
    const step5Count = await db.collection("leads").countDocuments({
      followupStep: 5,
      status: { $ne: "perdido" },
      statusOperacional: { $ne: "perdido_cadencia_completa" }
    });
    const step5Sample = await db.collection("leads").find(
      { followupStep: 5, status: { $ne: "perdido" } },
      { projection: {
          user: 1, status: 1, statusOperacional: 1, followupStep: 1,
          proximoFollowupEm: 1, reativadoPeloDashboardEm: 1, ultimoFollowupEm: 1
        }
      }
    ).limit(20).toArray();
    result.queryC_step5SemEncerramento = {
      count: step5Count,
      amostra: step5Sample
    };

    // QUERY D â cadĂȘncia fantasma
    result.queryD_cadenciaFantasma = await db.collection("leads").countDocuments({
      followupStep: { $gt: 0 },
      proximoFollowupEm: null,
      status: { $nin: ["perdido", "fechado"] }
    });

    // QUERY E â distribuiĂ§ĂŁo status Ă statusOperacional
    result.queryE_statusVsStatusOperacional = await db.collection("leads").aggregate([
      { $group: { _id: { status: "$status", op: "$statusOperacional" }, count: { $sum: 1 } } },
      { $sort: { count: -1 } }
    ]).toArray();

    // QUERY F â leads cujo user termina em "11" (procurar 5544*****11)
    const leads11 = await db.collection("leads").find(
      { user: { $regex: /11$/ } },
      { projection: {
          user: 1, followupStep: 1, status: 1, statusOperacional: 1,
          proximoFollowupEm: 1, ultimoFollowupEm: 1,
          reativadoPeloDashboardEm: 1, followupVersionDb: 1,
          nome: 1, encerradoPor: 1
        }
      }
    ).limit(20).toArray();
    result.queryF_leadsRegex11 = leads11;

    // QUERY G â audit events de followup do lead 5544*****11
    const candidatos5544 = leads11.filter(l =>
      typeof l.user === "string" && l.user.startsWith("5544") && l.user.endsWith("11")
    );
    if (candidatos5544.length === 1) {
      const userReal = candidatos5544[0].user;
      const events = await db.collection("audit_events").find(
        { userPhone: userReal, eventType: { $regex: "followup" } },
        { projection: {
            timestamp: 1, eventType: 1,
            "payload.step": 1, "payload.followupStep": 1,
            "payload.evento": 1, "payload.proximoStep": 1,
            "payload.stepAnterior": 1
          }
        }
      ).sort({ timestamp: 1 }).toArray();
      result.queryG_auditEventsLead11 = {
        userIdentificado: userReal,
        totalEvents: events.length,
        events
      };
    } else {
      result.queryG_auditEventsLead11 = {
        userIdentificado: null,
        candidatosEncontrados: candidatos5544.length,
        candidatos: candidatos5544.map(l => l.user),
        nota: candidatos5544.length === 0
          ? "Nenhum lead com user comeĂ§ando em 5544 e terminando em 11"
          : "MĂșltiplos candidatos â desambiguar manualmente antes de re-rodar"
      };
    }

    // QUERY H â mensagens do Edson com tag "Ao desenvolvedor"
    const allCollections = await db.listCollections().toArray();
    const collectionNames = allCollections.map(c => c.name);
    const conversationCandidate = collectionNames.find(n =>
      ["conversations", "messages", "conversation_history"].includes(n)
    );

    if (!conversationCandidate) {
      result.queryH_msgsAoDesenvolvedor = {
        collectionsEncontradas: collectionNames,
        nota: "Nenhuma collection de conversa identificada (conversations/messages/conversation_history)"
      };
    } else {
      const conversaEdson = await db.collection(conversationCandidate).findOne(
        { user: "5554996223975" },
        { projection: { messages: { $slice: -100 } } }
      );

      const flagged = [];
      const totalMensagens = (conversaEdson && Array.isArray(conversaEdson.messages))
        ? conversaEdson.messages.length
        : 0;

      if (conversaEdson && Array.isArray(conversaEdson.messages)) {
        conversaEdson.messages.forEach((m, i) => {
          const content = String(m.content || "");
          if (m.role === "user" && /ao desenvolvedor|ao claude|favor validar/i.test(content)) {
            const prev = conversaEdson.messages[i - 1];
            const next = conversaEdson.messages[i + 1];
            flagged.push({
              index: i,
              timestamp: m.timestamp || m.createdAt || null,
              sdrAnterior: prev ? String(prev.content || "").slice(0, 600) : null,
              edsonMsg: content,
              sdrPosterior: next ? String(next.content || "").slice(0, 600) : null
            });
          }
        });
      }

      result.queryH_msgsAoDesenvolvedor = {
        collectionUsada: conversationCandidate,
        leadDocumentExiste: conversaEdson !== null,
        totalMensagensAnalisadas: totalMensagens,
        marcacoesEncontradas: flagged.length,
        marcacoes: flagged
      };
    }

    return res.json(result);

  } catch (error) {
    console.error("Erro em /diagnostico-22-05-2026:", error);
    return res.status(500).json({
      ok: false,
      error: error.message,
      stack: error.stack
    });
  }
});

/* =========================
   ROTA DE DIAGNĂSTICO â auditoria forense 22/05/2026 BIS
   Uso: GET /diagnostico-22-05-2026-bis?senha=SENHA
   Read-only. Query I â audit_events de followup dos 12 leads em step 5.
   ========================= */
app.get("/diagnostico-22-05-2026-bis", async (req, res) => {
  if (!requireDashboardAuth(req, res)) return;

  try {
    await connectMongo();

    const result = {
      geradoEm: new Date().toISOString(),
      descricao: "DiagnĂłstico forense 22/05/2026 bis â audit events de followup dos 12 leads em step 5"
    };

    const users = [
      "5514991168002",
      "554498810007",
      "556291976462",
      "554191562241",
      "5521998831065",
      "559180802440",
      "554488430811",
      "555391665576",
      "556796495136",
      "557588386322",
      "555191989781",
      "554498820362"
    ];

    const seteDiasAtrasMs = Date.now() - 7 * 24 * 60 * 60 * 1000;
    const queryI = {};

    for (const user of users) {
      const events = await db.collection("audit_events").find(
        { userPhone: user, eventType: { $regex: "followup" } },
        { projection: {
            timestamp: 1, eventType: 1,
            "payload.step": 1, "payload.followupStep": 1,
            "payload.evento": 1, "payload.respostaFinalSdr": 1,
            "payload.closeAfter": 1, "payload.stepAnterior": 1,
            "payload.proximoStep": 1
          }
        }
      ).sort({ timestamp: -1 }).limit(15).toArray();

      const eventosUltimos7d = events.filter(e => {
        const ts = e.timestamp ? new Date(e.timestamp).getTime() : 0;
        return ts >= seteDiasAtrasMs;
      });

      const teveCadenciaCompleta = events.some(e =>
        e.payload?.evento === "cadencia_completa_lead_perdido"
      );

      const step5ComCloseAfter = events.some(e =>
        (e.payload?.step === 5 || e.payload?.followupStep === 5) &&
        e.payload?.closeAfter === true
      );

      const ultimoEvento = events[0] || null;

      queryI[user] = {
        totalEventosAll: events.length,
        countEventos7d: eventosUltimos7d.length,
        teveCadenciaCompletaLeadPerdido: teveCadenciaCompleta,
        algumStep5ComCloseAfter: step5ComCloseAfter,
        ultimoEvento: ultimoEvento ? {
          timestamp: ultimoEvento.timestamp,
          eventType: ultimoEvento.eventType,
          payload: ultimoEvento.payload
        } : null,
        eventos: events
      };
    }

    result.queryI_auditEventsPorUser = queryI;

    return res.json(result);

  } catch (error) {
    console.error("Erro em /diagnostico-22-05-2026-bis:", error);
    return res.status(500).json({
      ok: false,
      error: error.message,
      stack: error.stack
    });
  }
});

